const DISSOLVED_TEAMS = new Set(['Team Muse', 'Team Layover']);
const isTeamDissolved = team => DISSOLVED_TEAMS.has(team);

const teamColor = team => CONFIG.TEAMS[team]?.color || '#ff0000';

const teamPfp = team => CONFIG.TEAM_PFPS[team] || '';

/**
 * Resolve an agent's avatar. Returns their chosen badge image if they've set one
 * AND it's still valid (streak maintained — pfpValidThrough >= today KST);
 * otherwise falls back to their team PFP. Works for self and other agents.
 * @param {object} agent - object with {team|profile.team, pfpBadgeUrl, pfpValidThrough}
 */
function agentAvatar(agent) {
  if (!agent) return '';
  const team = agent.team || agent.profile?.team;
  const url = agent.pfpBadgeUrl;
  const valid = agent.pfpValidThrough;
  if (url && valid && valid >= getKSTDateString()) return url;
  return teamPfp(team);
}

/**
 * Badge-avatar URLs may carry a focal-point fragment: "…/img.jpg#fp=X,Y"
 * (X/Y = object-position percentages picked in the avatar adjuster).
 * Browsers ignore URL fragments when fetching images, so the raw URL still
 * loads anywhere it isn't parsed — this just enables nicer cropping where it is.
 * Returns { src, pos } — pos is a CSS object-position value.
 */
function avatarParts(url) {
  const m = String(url || '').match(/^(.*?)#fp=(\d{1,3}),(\d{1,3})$/);
  if (!m) return { src: url || '', pos: '50% 50%' };
  return { src: m[1], pos: `${Math.min(100, +m[2])}% ${Math.min(100, +m[3])}%` };
}

/** True if the agent is currently showing a custom (earned) badge avatar — used
 *  to apply the holo "C+" ring only to badge avatars, not team PFPs. */
function isBadgeAvatar(agent) {
  if (!agent) return false;
  const url = agent.pfpBadgeUrl;
  const valid = agent.pfpValidThrough;
  return !!(url && valid && valid >= getKSTDateString());
}

// If emoji is empty, we return an image tag pointing to the PFP!
const teamEmoji = team => {
  const emoji = CONFIG.TEAMS[team]?.emoji;
  if (emoji) return emoji;

  const pfp = teamPfp(team);
  if (pfp) return `<img src="${pfp}" style="width:100%; height:100%; object-fit:cover; border-radius:50%;" alt="${team}">`;

  return '🎵'; // Ultimate fallback
};

/**
 * Sanitize string to prevent XSS
 * v2.0: Added backtick escaping
 */
function sanitize(str) {
  if (!str) return '';
  const map = { '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;', '&': '&amp;', '`': '&#96;' };
  return String(str).replace(/[<>"'&`]/g, c => map[c] || c);
}


// ==================== DATE HELPERS ====================
/** Get current date string in KST timezone (YYYY-MM-DD) */
function getKSTDateString() {
  const kst = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Seoul' }));
  return `${kst.getFullYear()}-${String(kst.getMonth() + 1).padStart(2, '0')}-${String(kst.getDate()).padStart(2, '0')}`;
}

/** Format ISO date to readable "Mar 22, 3:45 PM IST" */
/** 
* Formats a date string to a readable "Mar 22, 3:45 PM IST" 
* v2.0: Supports both names to prevent ReferenceErrors
*/
function timeAgo(dateStr) {
  if (!dateStr) return 'Unknown';
  try {
    const d = new Date(dateStr);
    if (isNaN(d.getTime())) return dateStr;
    return d.toLocaleString('en-US', {
      timeZone: 'Asia/Kolkata', // Matches your config
      month: 'short',
      day: 'numeric',
      hour: 'numeric',
      minute: '2-digit',
      hour12: true
    }) + ' IST';
  } catch (e) {
    return dateStr;
  }
}

// Create the alias so pages calling "formatTimeAgo" don't crash
const formatTimeAgo = timeAgo;

/** Get remaining days for a given week label */
function getDaysRemaining(weekLabel) {
  const startStr = CONFIG.WEEK_DATES?.[weekLabel];
  if (!startStr) return 7;
  // Use KST midnight as the deadline so agents in all timezones see the correct count
  const weekStart = new Date(startStr + 'T00:00:00+09:00');
  const end = new Date(weekStart.getTime() + 7 * 86_400_000);
  return Math.max(0, Math.ceil((end - Date.now()) / 86_400_000));
}

/** Check if a week's end date has passed */
function isWeekCompleted(weekLabel) {
  const startStr = CONFIG.WEEK_DATES?.[weekLabel];
  if (!startStr) return false;
  const [y, m, d] = startStr.split('-').map(Number);
  return Date.now() >= new Date(y, m - 1, d + 7).getTime();
}
/** Get array of 7 date strings (YYYY-MM-DD) for a specific week */
function getWeekDates(weekLabel) {
  const startStr = CONFIG.WEEK_DATES?.[weekLabel];
  const dates = [];

  if (startStr) {
    // Parse safely as UTC to prevent local timezone shifts
    const start = new Date(startStr + 'T00:00:00Z');
    for (let i = 0; i < 7; i++) {
      dates.push(new Date(start.getTime() + i * 86400000).toISOString().split('T')[0]);
    }
  } else {
    // Fallback: Generate current Sun-Sat week if missing
    for (let i = 0; i < 7; i++) {
      const d = new Date();
      d.setDate(d.getDate() - d.getDay() + i);
      dates.push(d.toISOString().split('T')[0]);
    }
  }
  return dates;
}
/** Check if all side missions are passed today (Client-side verification) */
function isSideMissionPassedToday(sm) {
  if (!sm || !sm.tracks || sm.tracks.length === 0) return false;
  // If backend explicitly says true, trust it
  if (sm.todayAllPassed === true) return true;

  // Otherwise, check individual track progress for the current mission day
  const today = sm.today || getKSTDateString();
  return sm.tracks.every(t => {
    const dayData = t.daily?.[today];
    return !!dayData?.passed;
  });
}


