// =============================================
// ██████  NEW IN v2.0: API CLIENT
// =============================================
// Features:
//  • Response caching with configurable TTL
//  • In-flight request deduplication
//  • 15s timeout via AbortController
//  • Selective cache invalidation
//  • Silent mode for background requests
// =============================================
const Api = {
  _cache: new Map(),
  _pending: new Map(),

  /**
   * Make an API call with optional caching and dedup.
   *
   * @param {string} action — API action name
   * @param {object} [params={}] — Additional payload
   * @param {object} [opts={}] — Options
   * @param {boolean} [opts.cache=false] — Cache the response
   * @param {number}  [opts.ttl=30000] — Cache TTL in ms
   * @param {boolean} [opts.dedupe=true] — Deduplicate in-flight requests
   * @param {boolean} [opts.silent=false] — Suppress console errors
   * @returns {Promise<object>}
   *
   * @example
   * // Normal call
   * const data = await Api.call('getDashboardData');
   *
   * // Cached for 60s, deduped
   * const feed = await Api.call('getActivityFeed', { limit: 5 }, { cache: true, ttl: 60000 });
   *
   * // Silent background call
   * await Api.call('heartbeat', {}, { silent: true, dedupe: false });
   */
  async call(action, params = {}, opts = {}) {
    const { cache = false, ttl = 30_000, dedupe = true, silent = false, timeout = 20_000 } = opts;
    const key = this._key(action, params);

    // 1) Check cache
    if (cache) {
      const hit = this._cache.get(key);
      if (hit && (Date.now() - hit.ts < ttl)) {
        return hit.data;
      }
    }

    // 2) Deduplicate in-flight requests
    if (dedupe && this._pending.has(key)) {
      console.log(`API [${action}] Piggybacking on pending request...`);
      return await this._pending.get(key);
    }

    // 3) Fire the request
    const promise = (async () => {
      try {
        const data = await this._request(action, params, silent, 1, timeout);
        if (!data) throw new Error('Received empty/undefined data from _request');
        return data;
      } catch (err) {
        throw err;
      }
    })();

    if (dedupe) {
      this._pending.set(key, promise);
    }

    try {
      const data = await promise;

      // 4) Cache successful responses
      if (cache && data) {
        this._cache.set(key, { data, ts: Date.now() });
      }

      return data;
    } catch (err) {
      console.error(`API [${action}] Call failed:`, err.message);
      return {
        success: false,
        error: err.message || 'Connection Error',
        _exception: err
      };
    } finally {
      if (dedupe) this._pending.delete(key);
    }
  },

  /** Internal fetch with AbortController timeout + retry */
  async _request(action, params, silent, _attempt = 1, timeout = 20_000) {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    try {
      const res = await fetch(CONFIG.API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${CONFIG.SUPABASE_ANON_KEY}`,
        },
        signal: controller.signal,
        body: JSON.stringify({
          action,
          agentNo: STATE.agentNo,
          week: STATE.week,
          _cb: Date.now(),
          ...params,
        }),
      });

      if (!res.ok) throw new Error(`Server Error: ${res.status}`);
      const data = await res.json();
      if (data.error && !data.success) throw new Error(data.error);
      return data;

    } catch (err) {
      // Auto-retry ONCE on transient network errors (mobile WiFi↔LTE switches etc.)
      const isTransient = err.name === 'TypeError' || err.message === 'Failed to fetch' || err.message === 'Network request failed';
      if (isTransient && _attempt < 2) {
        if (!silent) console.warn(`API [${action}]: transient network error, retrying in 2s…`);
        await new Promise(r => setTimeout(r, 2000));
        return this._request(action, params, silent, 2, timeout);
      }
      if (err.name === 'AbortError') throw new Error('Request timed out — check your connection and retry');
      throw err;
    } finally {
      clearTimeout(timeoutId); // always clear — fixes timer leak on success path
    }
  },

  /** Build a cache key from action + params */
  _key(action, params) {
    // Exclude agentNo/week from key since they come from STATE
    return `${action}::${JSON.stringify(params)}`;
  },

  /**
   * Invalidate cache entries.
   * @param {string} [pattern] — If provided, only invalidate keys containing this string.
   *                              If omitted, clears entire cache.
   */
  invalidate(pattern) {
    if (!pattern) {
      this._cache.clear();
      return;
    }
    for (const key of this._cache.keys()) {
      if (key.includes(pattern)) this._cache.delete(key);
    }
  },
  async useEmergencySave(params) {
    return this.call('useEmergencySave', params, { dedupe: false, cache: false });
  },

  async getTeamBadgeHolders(params) {
    return this.call('getTeamBadgeHolders', params, { cache: false });
  },

  async getRescueSuggestions(params) {
    return this.call('getRescueSuggestions', params, { cache: true, ttl: 60000 });
  }
};

// Legacy alias — old code uses `api('action', params)`
// v2.0: Wraps new ApiClient for backward compatibility
async function api(action, params = {}) {
  return Api.call(action, params);
}


// ==================== TOAST SYSTEM ====================
// v2.0: Queue-based, prevents toast stacking, guaranteed cleanup
const Toast = {
  _current: null,
  _queue: [],

  /**
   * Show a toast notification
   * @param {string} msg
   * @param {'success'|'error'|'info'} [type='info']
   */
  show(msg, type = 'info') {
    // If a toast is already showing, replace it immediately
    if (this._current) {
      this._current.remove();
      this._current = null;
    }

    const colors = {
      success: { bg: 'rgba(0,40,0,0.95)', border: '#00ff66', icon: '✅' },
      error: { bg: 'rgba(40,0,0,0.95)', border: '#ff0000', icon: '⚠️' },
      info: { bg: 'rgba(20,20,20,0.95)', border: '#ff0000', icon: 'ℹ️' },
    };
    const c = colors[type] || colors.info;

    const el = document.createElement('div');
    el.className = 'toast-mini';
    el.innerHTML = `<span>${c.icon}</span><span>${sanitize(msg)}</span>`;
    el.style.cssText = `
        position:fixed;top:16px;left:50%;transform:translateX(-50%) translateY(-80px);
        padding:10px 18px;background:${c.bg};border:1px solid ${c.border};
        color:#fff;display:inline-flex;align-items:center;gap:8px;font-size:12px;
        z-index:999999;opacity:0;transition:all 0.3s ease;
        box-shadow:0 4px 20px rgba(0,0,0,0.5);
        font-weight:700;text-transform:uppercase;letter-spacing:1px;
        border-radius:4px;max-width:90vw;
      `;
    document.body.appendChild(el);
    this._current = el;

    // Animate in
    requestAnimationFrame(() => {
      el.style.opacity = '1';
      el.style.transform = 'translateX(-50%) translateY(0)';
    });

    // Auto-dismiss
    Timers.setTimeout('toast-dismiss', () => {
      el.style.opacity = '0';
      el.style.transform = 'translateX(-50%) translateY(-80px)';
      Timers.setTimeout('toast-remove', () => {
        el.remove();
        if (this._current === el) this._current = null;
      }, 300);
    }, 4000);
  },
};
/**
 * Show Emergency Save (Rescue Squad) Modal
 */
