// =============================================
// ██████  LEAVE / ATTENDANCE ACTIONS
// =============================================
// v2.0: Cache invalidation after each action ensures fresh data.

/**
 * Wrapper for leave/attendance API actions.
 * Handles confirmation, API call, toast, and dashboard reload.
 */
async function performAction(actionName, opts = {}) {
  const { confirmMsg, successMsg, errorMsg } = opts;

  if (confirmMsg && !confirm(confirmMsg)) return;

  try {
    const d = await Api.call(actionName, { agentNo: STATE.agentNo }, { dedupe: false, cache: false });

    if (d.success) {
      showToast(successMsg || 'Done!', 'success');
      Api.invalidate(); // Fresh data on next load
      loadDashboard();
    } else {
      showToast(d.error || errorMsg || 'Failed', 'error');
    }
  } catch {
    showToast(errorMsg || 'Action failed', 'error');
  }
}

function applyLeave() {
  performAction('applyLeave', {
    confirmMsg: 'Apply leave? You earn 0 XP but team is unaffected.',
    successMsg: 'Leave applied!',
    errorMsg: 'Failed to apply leave',
  });
}

function cancelLeave() {
  performAction('cancelLeave', {
    confirmMsg: 'Cancel leave? You will be back on duty.',
    successMsg: 'Leave cancelled!',
    errorMsg: 'Failed to cancel leave',
  });
}

function submitAttendance() {
  performAction('submitAttendance', {
    successMsg: 'Attendance submitted! 📸',
    errorMsg: 'Failed to submit',
  });
}


// =============================================
// ██████  BADGE SYSTEM
// =============================================

/**
 * Deterministic badge selection from seed.
 * Same agent + same milestone → always same badge.
 */
function getBadgeForSeed(seed) {
  const pool = CONFIG.BADGE_POOL;
  if (!pool || pool.length === 0) return '';
  return pool[Math.abs(seed) % pool.length];
}

// =============================================
// BADGE FREEZING — once a badge's picture is shown, it's locked forever.
// Adding new images to the pool can never change an already-earned badge.
// =============================================
let _badgeFreezeQueue = [];
let _badgeFreezeTimer = null;

/** Load this agent's permanently-frozen badge images. Always fetches fresh so a
 *  recent "Lock All" / restore is reflected immediately. */
async function loadFrozenBadges() {
  if (!STATE.agentNo) return;
  try {
    const r = await Api.call('getFrozenBadges', { agentNo: STATE.agentNo }, { dedupe: false, cache: false });
    STATE.frozenBadges = (r && r.success && r.frozen) ? r.frozen : (STATE.frozenBadges || {});
  } catch (_) {
    STATE.frozenBadges = STATE.frozenBadges || {};
  }
}

/**
 * Return the locked image for a badge if one exists; otherwise lock the freshly
 * computed image and persist it. After the first view a badge's picture is permanent.
 * @param {string} key  Stable unique badge identity (agent + type + week + index)
 * @param {string} computedUrl  The image the current pool would pick
 */
function resolveBadgeImage(key, computedUrl) {
  if (!key) return computedUrl;
  if (!STATE.frozenBadges) STATE.frozenBadges = {};
  const locked = STATE.frozenBadges[key];
  if (locked) return locked;               // already permanent → use it
  // First time seen: lock the current pick and queue it for the server
  STATE.frozenBadges[key] = computedUrl;
  _badgeFreezeQueue.push({ key, url: computedUrl });
  if (_badgeFreezeTimer) clearTimeout(_badgeFreezeTimer);
  _badgeFreezeTimer = setTimeout(_flushBadgeFreezes, 1500);
  return computedUrl;
}

async function _flushBadgeFreezes() {
  const batch = _badgeFreezeQueue.splice(0, _badgeFreezeQueue.length);
  if (!batch.length || !STATE.agentNo) return;
  try {
    await Api.call('freezeBadges', { agentNo: STATE.agentNo, badges: batch }, { dedupe: false, cache: false });
  } catch (_) { /* will retry on next view */ }
}

/**
 * Get all level badges an agent has earned (1 per 50 XP).
 * @returns {Array<{name: string, description: string, imageUrl: string, type: string}>}
 */
function getLevelBadges(agentNo, totalXP, weekName = STATE.week) {
  const badges = [];
  const xp = parseInt(totalXP) || 0;
  const count = Math.floor(xp / 50);

  for (let i = 1; i <= count; i++) {
    // Multiplicative hash (FNV-1a inspired) — 1-char difference gives completely different result
    let seed = 0x811c9dc5;
    const str = String(agentNo).toUpperCase() + 'LEVEL' + (weekName || '') + i;
    for (let c = 0; c < str.length; c++) {
      seed ^= str.charCodeAt(c);
      seed = Math.imul(seed, 0x01000193) | 0;
    }
    seed = Math.abs(seed);

    badges.push({
      name: `${i * 50} XP`,
      description: `Earned at ${i * 50} XP`,
      imageUrl: resolveBadgeImage(`xp:${String(agentNo).toUpperCase()}:${weekName || ''}:${i}`, getBadgeForSeed(seed)),
      type: 'xp',
    });
  }

  return badges.reverse(); // Most recent first
}

/**
 * Get Elite Tactical Badges (1 per 100 XP), minus any that were consumed by Emergency Saves.
 * @param {number} consumed - number of merits spent this week (from merit_consumptions)
 */
function getTacticalBadges(agentNo, totalXP, weekName = STATE.week, consumed = 0) {
  const badges = [];
  const earnedCount = Math.floor(totalXP / 100);
  const pool = CONFIG.TACTICAL_POOL;
  if (!pool || pool.length === 0) return badges; // guard against missing config

  for (let i = 1; i <= earnedCount; i++) {
    // Multiplicative hash (FNV-1a inspired) — ensures scattered pool selection
    // even for agents with sequential IDs or consecutive badge indices
    let seed = 0x811c9dc5;
    const str = String(agentNo).toUpperCase() + "TACTICAL" + (weekName || "") + i;
    for (let c = 0; c < str.length; c++) {
      seed ^= str.charCodeAt(c);
      seed = Math.imul(seed, 0x01000193) | 0;
    }
    seed = Math.abs(seed);
    badges.push({ name: `Elite ${i}`, imageUrl: resolveBadgeImage(`tac:${String(agentNo).toUpperCase()}:${weekName || ''}:${i}`, pool[seed % pool.length]) });
  }
  badges.reverse(); // most recently earned first

  // Remove consumed merits (they are spent from the most recently earned)
  const remaining = Math.max(0, badges.length - consumed);
  return badges.slice(0, remaining);
}

/**
 * Get Album 2X achievement badge for a given week.
 * Caller is responsible for verifying the agent passed 2X that week.
 * @returns {object|null}
 */
function getAlbum2xBadge(agentNo, weekName) {
  const pool = CONFIG.BADGE_POOL;
  if (!pool?.length) return null;

  // FNV-1a hash — consistent with getLevelBadges and getTacticalBadges
  let seed = 0x811c9dc5;
  const str = String(agentNo).toUpperCase() + '_ALBUM_' + (weekName || '');
  for (let i = 0; i < str.length; i++) {
    seed ^= str.charCodeAt(i);
    seed = Math.imul(seed, 0x01000193) | 0;
  }
  seed = Math.abs(seed);

  return {
    name: CONFIG.ALBUM_CHALLENGE.BADGE_NAME,
    description: `${CONFIG.ALBUM_CHALLENGE.BADGE_DESCRIPTION} (${weekName})`,
    imageUrl: resolveBadgeImage(`alb:${String(agentNo).toUpperCase()}:${weekName || ''}`, pool[seed % pool.length]),
    type: 'achievement',
    icon: '✨',
  };
}


