const VAPID_PUBLIC_KEY = 'BLaBF_JxPyDPSd-76mhZxFnvyxcHCY-bdNSKKFjLlLsAWxJkAGYx4_LffeSqpNSwyF1ajVLX7Z_iz_b2TCuIbQQ';

