async function saveLibreFmUsername() {
  const input = document.getElementById('libre-fm-input');
  const status = document.getElementById('libre-save-status');
  const username = input?.value?.trim();
  if (!username) { toast('Enter your Libre.fm username'); return; }
  if (status) status.innerHTML = `<span style="color:var(--text-muted);">Saving…</span>`;

  try {
    const d = await Api.call('saveLibreFmUsername', { agentNo: STATE.agentNo, libreFmUsername: username }, { cache: false });
    if (!d?.success) {
      if (status) status.innerHTML = `<span style="color:var(--fail);">${d?.error || 'Something went wrong.'}</span>`;
      return;
    }
    if (STATE.data?.agent?.profile) STATE.data.agent.profile.libreFmUsername = username;
    renderSpotifyBetaCard();
  } catch (e) {
    if (status) status.innerHTML = `<span style="color:var(--fail);">Error saving — try again.</span>`;
  }
}

function renderScrobblerCard() {
  const card = document.getElementById('scrobbler-card');
  if (!card) return;
  const pin = STATE.data?.agent?.profile?.scrobblePin || null;
  const agentNo = STATE.agentNo || '';
  const ENDPOINT = CONFIG.API_URL;
  const PANO_COLOR = '#f59e0b';

  card.innerHTML = `
    <div class="archive-card" style="border-color:rgba(245,158,11,0.4); background:rgba(245,158,11,0.03); margin-bottom:0;">
      <div style="display:flex; align-items:center; gap:10px; margin-bottom:14px;">
        <span style="font-size:18px;">🎙️</span>
        <div>
          <div style="font-size:11px; font-weight:900; color:${PANO_COLOR}; letter-spacing:1px;">
            PANO SCROBBLER
            <span style="font-size:8px; background:rgba(245,158,11,0.2); color:${PANO_COLOR}; border:1px solid rgba(245,158,11,0.4); padding:1px 6px; border-radius:4px; margin-left:4px; letter-spacing:1.5px;">DIRECT</span>
          </div>
          <div style="font-size:10px; color:var(--text-muted); margin-top:2px;">Scrobble from any app — Spotify, Apple Music, YouTube Music, Melon — directly to Arirang</div>
        </div>
      </div>

      ${pin ? `
        <div style="background:rgba(34,197,94,0.06); border:1px solid rgba(34,197,94,0.25); border-radius:8px; padding:12px 14px; margin-bottom:12px;">
          <div style="font-size:9px; color:#4ade80; font-weight:800; text-transform:uppercase; letter-spacing:1px; margin-bottom:8px;">Your Scrobbler Credentials</div>
          <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:6px;">
            <span style="font-size:10px; color:var(--text-muted);">Username</span>
            <span style="font-family:var(--font-mono); font-size:12px; color:#fff; font-weight:700;">${sanitize(agentNo)}</span>
          </div>
          <div style="display:flex; justify-content:space-between; align-items:center;">
            <span style="font-size:10px; color:var(--text-muted);">PIN (password)</span>
            <span style="font-family:var(--font-mono); font-size:13px; color:${PANO_COLOR}; font-weight:900; letter-spacing:2px;">${sanitize(pin)}</span>
          </div>
        </div>
        <div style="background:rgba(245,158,11,0.07); border:1px solid rgba(245,158,11,0.2); border-radius:8px; padding:10px 12px; margin-bottom:12px;">
          <div style="font-size:9px; color:${PANO_COLOR}; font-weight:800; text-transform:uppercase; letter-spacing:1px; margin-bottom:6px;">Pano Scrobbler Setup</div>
          <div style="font-size:10px; color:var(--text-secondary); line-height:1.8;">
            1. Open Pano Scrobbler → <strong style="color:#fff;">Add Service</strong><br>
            2. Select <strong style="color:#fff;">ListenBrainz-like instance</strong><br>
            3. URL: <span style="font-family:var(--font-mono); font-size:9px; color:${PANO_COLOR}; word-break:break-all;">${ENDPOINT}</span><br>
            4. Token: <strong style="color:#fff;">${sanitize(pin)}</strong>
          </div>
        </div>
        <button onclick="generateScrobblePin()"
          style="width:100%; padding:8px; background:transparent; border:1px solid rgba(245,158,11,0.3);
            border-radius:8px; color:${PANO_COLOR}; font-size:10px; font-weight:700; cursor:pointer;">
          🔄 Regenerate PIN
        </button>
      ` : `
        <div style="font-size:10px; color:var(--text-secondary); line-height:1.6; margin-bottom:12px;">
          Generate a PIN to connect Pano Scrobbler. Every stream you play — on any platform — will count automatically.
        </div>
        <button onclick="generateScrobblePin()"
          style="width:100%; padding:10px; background:${PANO_COLOR}; border:none;
            border-radius:8px; color:#000; font-size:11px; font-weight:900; cursor:pointer;">
          🎙️ Generate Scrobble PIN
        </button>
      `}
      <div id="scrobbler-status" style="font-size:9px; color:var(--text-ghost); text-align:center; margin-top:8px;"></div>
    </div>`;
}

async function generateScrobblePin() {
  const status = document.getElementById('scrobbler-status');
  if (status) status.innerHTML = `<span style="color:var(--text-muted);">Generating…</span>`;
  try {
    const d = await Api.call('generateScrobblePin', { agentNo: STATE.agentNo }, { cache: false });
    if (!d?.success) {
      if (status) status.innerHTML = `<span style="color:var(--fail);">${d?.error || 'Error'}</span>`;
      return;
    }
    if (STATE.data?.agent?.profile) STATE.data.agent.profile.scrobblePin = d.pin;
    renderScrobblerCard();
  } catch (_) {
    if (status) status.innerHTML = `<span style="color:var(--fail);">Error — try again.</span>`;
  }
}

async function previewLibreFm() {
  const area = document.getElementById('libre-status-area');
  if (!area) return;
  const username = STATE.data?.agent?.profile?.libreFmUsername || '';
  if (!username) { toast('No Libre.fm username saved'); return; }

  area.innerHTML = `<div style="font-size:10px; color:var(--text-muted); font-family:var(--font-mono); padding:6px 0;">Fetching from Libre.fm…</div>`;

  try {
    const d = await Api.call('previewLibreFm', { agentNo: STATE.agentNo, libreFmUsername: username, weekLabel: STATE.week }, { cache: false });

    if (!d?.success) {
      area.innerHTML = `<div style="font-size:10px; color:var(--fail); padding:6px 0;">${d?.error || 'Something went wrong.'}</div>`;
      return;
    }

    const LIBRE_COLOR = '#8b5cf6';
    const rows = Object.entries(d.counts || {})
      .sort(([, a], [, b]) => b.lbCount - a.lbCount)
      .map(([name, info]) => `
        <div style="display:flex; justify-content:space-between; align-items:center; padding:5px 0; border-bottom:1px solid rgba(255,255,255,0.05);">
          <span style="font-size:10px; color:var(--text-secondary);">${sanitize(name)}</span>
          <span style="font-size:10px; font-weight:900; font-family:var(--font-mono); color:${info.lbCount > 0 ? LIBRE_COLOR : 'var(--text-ghost)'};">
            ${info.lbCount} <span style="color:var(--text-ghost); font-weight:400;">/ ${info.goal}</span>
          </span>
        </div>`).join('');

    area.innerHTML = `
      <div style="font-size:9px; color:var(--text-ghost); margin-bottom:8px;">
        Scanned <strong style="color:${LIBRE_COLOR};">${d.listensScanned}</strong> scrobbles for <strong style="color:#fff;">${sanitize(d.libreFmUsername)}</strong> this week
      </div>
      <div style="margin-bottom:10px;">${rows || '<div style="font-size:10px;color:var(--text-ghost);">No matching streams found this week.</div>'}</div>
      <button onclick="previewLibreFm()"
        style="width:100%; padding:9px; background:transparent; border:1px solid rgba(139,92,246,0.3);
          border-radius:8px; color:${LIBRE_COLOR}; font-size:10px; font-weight:700; cursor:pointer;">
        ↺ Refresh
      </button>`;
  } catch (_) {
    area.innerHTML = `<div style="font-size:10px; color:var(--text-muted); padding:6px 0;">Libre.fm preview unavailable.</div>`;
  }
}

async function previewLB() {
  const input = document.getElementById('lb-username-input');
  const area = document.getElementById('lb-status-area');
  if (!area) return;

  // In connected state there's no input — fall back to the saved username in STATE
  const username = input ? input.value.trim() : (STATE.data?.agent?.profile?.lbUsername || '');
  if (!username) { toast('Enter your ListenBrainz username'); return; }

  area.innerHTML = `<div style="font-size:10px; color:var(--text-muted); font-family:var(--font-mono); padding:6px 0;">Fetching from ListenBrainz…</div>`;

  try {
    const d = await Api.call('previewListenBrainz', { agentNo: STATE.agentNo, lbUsername: username, weekLabel: STATE.week }, { cache: false });

    if (!d?.success) {
      area.innerHTML = `<div style="font-size:10px; color:var(--fail); padding:6px 0;">${d?.error || 'Something went wrong.'}</div>`;
      return;
    }

    const rows = Object.entries(d.counts || {})
      .sort(([, a], [, b]) => b.lbCount - a.lbCount)
      .map(([name, info]) => `
        <div style="display:flex; justify-content:space-between; align-items:center; padding:5px 0; border-bottom:1px solid rgba(255,255,255,0.05);">
          <span style="font-size:10px; color:var(--text-secondary);">${sanitize(name)}</span>
          <span style="font-size:10px; font-weight:900; font-family:var(--font-mono); color:${info.lbCount > 0 ? LB_COLOR : 'var(--text-ghost)'};">
            ${info.lbCount} <span style="color:var(--text-ghost); font-weight:400;">/ ${info.goal}</span>
          </span>
        </div>`).join('');

    area.innerHTML = `
      <div style="font-size:9px; color:var(--text-ghost); margin-bottom:8px;">
        Scanned last <strong style="color:${LB_COLOR};">${d.listensScanned}</strong> listens for <strong style="color:#fff;">${sanitize(d.lbUsername)}</strong>
      </div>
      <div style="margin-bottom:12px;">${rows || '<div style="font-size:10px;color:var(--text-ghost);">No matching streams found in recent listens.</div>'}</div>
      <div style="background:rgba(235,116,59,0.08); border:1px solid rgba(235,116,59,0.2); border-radius:8px; padding:10px 12px; margin-bottom:10px;">
        <div style="font-size:10px; color:var(--text-secondary); line-height:1.5; margin-bottom:8px;">
          👀 <strong style="color:#fff;">Does this look correct?</strong> This is a preview only — your official record is still from your scrobbler.
        </div>
        <div style="display:flex; gap:8px;" id="lb-feedback-row">
          <button onclick="submitLBFeedback('yes')"
            style="flex:1; padding:7px; background:rgba(34,197,94,0.15); border:1px solid rgba(34,197,94,0.35);
              border-radius:7px; color:#4ade80; font-size:11px; font-weight:900; cursor:pointer;">
            ✅ Yes, looks right
          </button>
          <button onclick="submitLBFeedback('no')"
            style="flex:1; padding:7px; background:rgba(239,68,68,0.1); border:1px solid rgba(239,68,68,0.25);
              border-radius:7px; color:#f87171; font-size:11px; font-weight:900; cursor:pointer;">
            ❌ No, something's off
          </button>
        </div>
        <div id="lb-feedback-thanks" style="display:none; font-size:10px; color:var(--text-ghost); text-align:center; margin-top:6px;"></div>
      </div>
      <button onclick="previewLB()"
        style="width:100%; padding:9px; background:transparent; border:1px solid rgba(235,116,59,0.3);
          border-radius:8px; color:${LB_COLOR}; font-size:10px; font-weight:700; cursor:pointer;">
        ↺ Refresh
      </button>`;
  } catch (_) {
    area.innerHTML = `<div style="font-size:10px; color:var(--text-muted); padding:6px 0;">ListenBrainz preview unavailable.</div>`;
  }
}

async function submitLBFeedback(answer) {
  const row = document.getElementById('lb-feedback-row');
  const thanks = document.getElementById('lb-feedback-thanks');
  if (!row || !thanks) return;
  row.style.display = 'none';
  thanks.style.display = 'block';
  thanks.innerHTML = `<span style="color:var(--text-ghost);">Saving…</span>`;

  const lbUsername = document.getElementById('lb-username-input')?.value?.trim()
    || STATE.data?.agent?.profile?.lbUsername || '';
  try {
    await Api.call('submitLBFeedback', {
      agentNo: STATE.agentNo,
      lbUsername,
      weekLabel: STATE.week,
      feedback: answer,
    }, { cache: false });
  } catch (_) {}

  if (answer === 'yes') {
    thanks.innerHTML = `<span style="color:#4ade80;">💜 Thank you! Glad it's working correctly.</span>`;
  } else {
    thanks.innerHTML = `<span style="color:#f87171;">Thank you for letting us know. Please reach out to your team admin with your username so we can investigate.</span>`;
  }
}

// ── END LISTENBRAINZ BETA ──────────────────────────────────────────────────────

async function checkFriendsWelcome() {
  if (!STATE.agentNo) return false;
  try {
    const d = await Api.call('checkFriendsWelcome', { agentNo: STATE.agentNo }, { cache: false });
    if (!d?.success || !d.showWelcome) return false;
    $('friendsWelcomeModal').hidden = false;
    return true;
  } catch (_) { return false; }
}

async function dismissFriendsWelcome() {
  $('friendsWelcomeModal').hidden = true;
  try { await Api.call('dismissFriendsWelcome', { agentNo: STATE.agentNo }, { cache: false }); } catch (_) {}
}

let _teamChoiceSelected = null;

async function checkPendingTeamChoice() {
  if (!STATE.agentNo) return;
  try {
    const d = await Api.call('getPendingTeamChoice', { agentNo: STATE.agentNo }, { cache: false });
    if (!d?.success || !d.hasPendingChoice) return;
    showTeamChoiceModal(d.deadline, d.availableTeams || []);
  } catch (_) {}
}

function showTeamChoiceModal(deadline, availableTeams) {
  const modal = $('teamChoiceModal');
  const grid  = $('teamChoiceGrid');
  const dl    = $('teamChoiceDeadline');
  if (!modal || !grid) return;

  _teamChoiceSelected = null;

  if (deadline && dl) {
    const d = new Date(deadline);
    dl.textContent = `⏳ Choose before ${d.toLocaleDateString('en-IN', { day:'numeric', month:'short', year:'numeric' })}`;
  }

  // Build team cards with live agent counts
  grid.innerHTML = availableTeams.map(t => {
    const meta = TEAM_CHOICE_META[t.name] || { short: t.name, color: '#fff', ref: '' };
    return `
      <div onclick="selectTeamChoice('${t.name}', this)"
        style="border:2px solid rgba(255,255,255,0.08);border-radius:10px;padding:14px 8px;
          text-align:center;cursor:pointer;transition:all 0.2s;background:rgba(255,255,255,0.03);"
        data-team="${t.name}">
        <div style="font-size:0.75rem;font-weight:900;letter-spacing:1.5px;color:${meta.color};">${meta.short}</div>
        <div style="font-size:0.6rem;color:var(--text-muted);margin-top:2px;">${meta.ref}</div>
        <div style="font-size:0.65rem;color:rgba(255,255,255,0.5);margin-top:5px;font-weight:700;">${t.count} agents</div>
      </div>`;
  }).join('');

  modal.hidden = false;
}

function selectTeamChoice(teamName, el) {
  _teamChoiceSelected = teamName;
  document.querySelectorAll('#teamChoiceGrid [data-team]').forEach(c => {
    c.style.border = '2px solid rgba(255,255,255,0.08)';
    c.style.background = 'rgba(255,255,255,0.03)';
  });
  const meta = TEAM_CHOICE_META[teamName];
  el.style.border = `2px solid ${meta?.color || '#7C5CBF'}`;
  el.style.background = `${meta?.color || '#7C5CBF'}18`;
  const btn = $('teamChoiceConfirmBtn');
  if (btn) { btn.disabled = false; btn.style.opacity = '1'; btn.style.pointerEvents = 'auto'; }
}

async function confirmTeamChoice() {
  if (!_teamChoiceSelected) return;
  const btn = $('teamChoiceConfirmBtn');
  const err = $('teamChoiceError');
  if (btn) { btn.disabled = true; btn.textContent = 'Saving…'; }
  if (err) err.textContent = '';
  try {
    const d = await Api.call('submitTeamChoice', { agentNo: STATE.agentNo, newTeam: _teamChoiceSelected }, { cache: false });
    if (d?.success) {
      const gcLink = CONFIG.GC_LINKS?.teams?.[_teamChoiceSelected] || '';
      const meta = TEAM_CHOICE_META[_teamChoiceSelected] || {};
      const modal = $('teamChoiceModal');
      modal.querySelector('.modal-card').innerHTML = `
        <div style="padding:28px 24px;text-align:center;">
          <div style="font-size:2.2rem;margin-bottom:10px;">💜</div>
          <div style="font-size:1rem;font-weight:900;color:#fff;margin-bottom:6px;">Welcome to ${_teamChoiceSelected}!</div>
          <div style="font-size:0.72rem;color:var(--text-muted);line-height:1.7;margin-bottom:20px;">
            Your XP, badges and stream history are all preserved.<br>Stream hard and represent your new team!
          </div>
          ${gcLink ? `
          <a href="${gcLink}" target="_blank" rel="noopener"
            style="display:block;padding:13px;background:${meta.color || '#7C5CBF'}22;
              border:1px solid ${meta.color || '#7C5CBF'}66;border-radius:10px;
              color:${meta.color || '#7C5CBF'};font-size:0.8rem;font-weight:900;
              letter-spacing:1px;text-decoration:none;margin-bottom:12px;">
            📲 Join ${_teamChoiceSelected} Group Chat
          </a>` : ''}
          <button onclick="$('teamChoiceModal').hidden=true;loadDashboard();"
            style="width:100%;padding:13px;background:linear-gradient(135deg,${meta.color || '#7C5CBF'},#4f46e5);
              border:none;border-radius:10px;color:#fff;font-size:0.8rem;font-weight:900;
              letter-spacing:1px;cursor:pointer;text-transform:uppercase;">
            Let's Go →
          </button>
        </div>`;
      setTimeout(() => loadDashboard(), 8000);
    } else {
      if (err) err.textContent = d?.error || 'Something went wrong — try again';
      if (btn) { btn.disabled = false; btn.textContent = 'Confirm Team'; }
    }
  } catch (_) {
    if (err) err.textContent = 'Connection error — try again';
    if (btn) { btn.disabled = false; btn.textContent = 'Confirm Team'; }
  }
}
// ─────────────────────────────────────────────────────────────

function closePasswordModal() {
  const modal = $('passwordModal');
  if (modal) modal.hidden = true;

  // Clear fields safely
  const fields = ['currentPw', 'newPw', 'confirmNewPw'];
  fields.forEach(id => {
    const el = $(id);
    if (el) el.value = '';
  });

  const errEl = $('pwError');
  if (errEl) errEl.textContent = '';
}

async function changePassword() {
  const current = $('currentPw')?.value;
  const newPw = $('newPw')?.value;
  const confirmPw = $('confirmNewPw')?.value;
  const errEl = $('pwError');

  // Validation
  if (!current || !newPw || !confirmPw) {
    if (errEl) errEl.textContent = 'Fill all fields';
    return;
  }
  if (newPw.length < 4) {
    if (errEl) errEl.textContent = 'Min 4 characters';
    return;
  }
  if (newPw !== confirmPw) {
    if (errEl) errEl.textContent = 'Passwords do not match';
    return;
  }

  try {
    const d = await Api.call('updatePassword', {
      agentNo: STATE.agentNo,
      oldPassword: current,
      newPassword: newPw,
    }, { dedupe: false, cache: false });

    if (d.success) {
      showToast('Password updated!', 'success');
      closePasswordModal();
    } else {
      if (errEl) errEl.textContent = d.error || 'Failed';
    }
  } catch (e) {
    if (errEl) errEl.textContent = 'Error: ' + e.message;
  }
}


// =============================================
// ██████  DELETE ACCOUNT
// =============================================

let _deleteInProgress = false;

async function deleteAccountConfirm() {
  if (_deleteInProgress) return;

  const pw = prompt('⚠️ DELETE ACCOUNT?\n\nThis is PERMANENT. Enter your password to confirm:');
  if (!pw) return;
  if (!confirm('FINAL WARNING: All your data will be erased. Continue?')) return;

  _deleteInProgress = true;
  Loading.show();

  try {
    const d = await Api.call('deleteAccount', {
      agentNo: STATE.agentNo,
      password: pw,
    }, { dedupe: false, cache: false });

    if (d.success) {
      showToast('Account deleted', 'info');
      doLogout();
    } else {
      showToast(d.error || 'Failed', 'error');
    }
  } catch (e) {
    showToast('Error: ' + e.message, 'error');
  } finally {
    Loading.hide();
    _deleteInProgress = false;
  }
}


// =============================================
// ██████  SONG OF THE DAY PAGE
// =============================================

async function renderSongOfDay() {
  const container = $('sotdContent');
  if (!container) return;

  showPageLoading(container);

  try {
    const todayKST = getKSTDateString();

    // Fetch today's song and history simultaneously
    const [d, historyRes] = await Promise.all([
      Api.call('getSongOfDay', { date: todayKST }, { cache: true, ttl: 300_000 }),
      Api.call('getSOTDHistory', { limit: 5 }, { cache: true, ttl: 300_000 })
    ]);

    const song = d.song;
    const answered = localStorage.getItem(`sotd_answered_${STATE.agentNo}_${todayKST}`);

    // ── HEADER ──
    let html = `
      <div class="archive-card" style="text-align:center; padding:30px 20px; border-top:3px solid var(--wave-foam); background:linear-gradient(135deg, rgba(74,144,164,0.05), var(--bg-panel)); margin-bottom:24px;">
        <div style="font-size:48px; margin-bottom:16px; filter:drop-shadow(0 4px 10px rgba(0,0,0,0.5));">🎬</div>
        <div style="font-size:14px; font-weight:900; color:#fff; text-transform:uppercase; letter-spacing:2px; font-family:'Orbitron', sans-serif; margin-bottom:8px;">Audio Intelligence Unit</div>
        <div style="font-size:11px; color:var(--wave-foam); letter-spacing:2px; font-family:'Share Tech Mono', monospace;">KST: ${todayKST}</div>
      </div>
    `;

    // ── NO SONG TODAY ──
    if (!d.success || !song) {
      html += `
        <div class="glass-card" style="text-align:center; padding:40px; color:var(--text-muted); font-size:12px;">
          No audio intercepted today. Stand by.
        </div>
      `;
      container.innerHTML = html;
      return;
    }

    // ── HINT ──
    if (song.hint) {
      html += `
        <div class="glass-card" style="padding:20px; text-align:center; margin-bottom:24px; border-color:var(--vinyl-gold); box-shadow:inset 0 0 30px rgba(212,175,55,0.05);">
          <div style="font-size:10px; color:var(--vinyl-gold); font-weight:900; letter-spacing:2px; text-transform:uppercase; margin-bottom:12px;">Intercepted Clue</div>
          <div style="font-size:14px; color:#fff; font-style:italic; line-height:1.6; text-shadow:0 2px 4px rgba(0,0,0,0.8);">"${sanitize(song.hint)}"</div>
          <div style="margin-top:16px; display:inline-block; padding:4px 12px; background:rgba(212,175,55,0.1); border:1px solid rgba(212,175,55,0.3); border-radius:12px; color:var(--vinyl-gold); font-size:10px; font-weight:800;">
            REWARD: +${song.xpReward || 1} XP
          </div>
        </div>
      `;
    }

    // ── ANSWER / ALREADY ANSWERED ──
    if (answered) {
      html += `
        <div class="glass-card" style="padding:30px 20px; text-align:center; border-left:4px solid var(--green); margin-bottom:24px;">
          <div style="font-size:40px; margin-bottom:12px;">✅</div>
          <div style="font-size:14px; font-weight:900; color:var(--green); letter-spacing:1px; text-transform:uppercase; margin-bottom:8px;">Decryption Successful</div>
          <div style="font-size:12px; color:var(--text-secondary);">You have successfully identified the track today.</div>
        </div>
      `;
    } else {
      html += `
        <div class="glass-card" style="padding:24px; margin-bottom:24px;">
          <label class="label-tag" style="display:block; margin-bottom:12px;">Submit YouTube URL</label>
          <input type="text" id="sotdAnswer" class="input-field" placeholder="https://youtube.com/watch?v=..." style="margin-bottom:16px;">
          <button class="btn-red" onclick="submitSongAnswer()" style="padding:16px; background:linear-gradient(135deg, var(--wave-foam), #1a4d60);">
            VERIFY DECRYPTION
          </button>
          <div id="sotdResult" style="margin-top:16px; text-align:center; font-size:12px; font-weight:700; min-height:20px;"></div>
          <div style="margin-top:20px; font-size:10px; color:var(--text-muted); text-align:center;">
            Max 2 attempts allowed. Enter the official MV or Audio link.
          </div>
        </div>
      `;
    }

    // ── HISTORY LEADERBOARD ──
    if (historyRes.success && historyRes.history?.length > 0) {
      html += `
        <div style="display:flex; align-items:center; gap:12px; margin:0 0 16px 0;">
          <div style="font-size:16px;">📜</div>
          <div style="font-size:11px; font-weight:800; text-transform:uppercase; letter-spacing:3px; color:var(--wave-foam);">Intelligence History</div>
          <div style="flex:1; height:1px; background:linear-gradient(90deg, rgba(74,144,164,0.3), transparent);"></div>
        </div>
      `;

      historyRes.history.forEach(item => {
        const winner = item.results?.winner || 'TBD';
        const winColor = winner !== 'TBD' ? teamColor(winner) : 'var(--text-ghost)';
        const teamData = item.results?.teams || {};

        // Sort teams by correct count descending
        const sortedTeams = Object.entries(teamData).sort((a, b) => b[1].correct - a[1].correct);

        html += `
          <div class="archive-card" style="margin-bottom:16px; padding:16px;">

            <!-- Song title + winner row -->
            <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:15px; border-bottom:1px solid rgba(255,255,255,0.05); padding-bottom:10px;">
              <div>
                <div style="font-size:12px; font-weight:800; color:#fff;">${sanitize(item.song?.title || 'Unknown')}</div>
                <div style="font-size:9px; color:var(--text-muted); font-family:monospace; margin-top:3px;">${item.date || ''}</div>
              </div>
              <div style="text-align:right; flex-shrink:0; margin-left:12px;">
                <div style="font-size:10px; font-weight:900; color:${winColor}; text-transform:uppercase; letter-spacing:1px;">
                  🏆 ${winner === 'TBD' ? 'TBD' : winner.replace('Team ', '') + ' WON'}
                </div>
                <div style="font-size:8px; color:var(--text-ghost); margin-top:3px;">
                  ${item.results?.totalParticipants || 0} TOTAL VOTES
                </div>
              </div>
            </div>

            <!-- Team scoreboard grid -->
            ${sortedTeams.length > 0 ? `
              <div style="display:grid; grid-template-columns:1fr 1fr; gap:8px;">
                ${sortedTeams.map(([tName, tStats]) => {
          const isWinner = tName === winner;
          return `
                    <div style="display:flex; justify-content:space-between; align-items:center; padding:6px 10px;
                      background:${isWinner ? 'rgba(0,255,102,0.05)' : 'rgba(255,255,255,0.02)'};
                      border-radius:6px;
                      border:1px solid ${isWinner ? 'rgba(0,255,102,0.15)' : 'rgba(255,255,255,0.04)'};">
                      <span style="font-size:10px; color:${teamColor(tName)}; font-weight:700; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">
                        ${isWinner ? '🏆 ' : ''}${tName.replace('Team ', '')}
                      </span>
                      <span style="font-size:11px; font-family:monospace; color:${isWinner ? 'var(--green)' : '#fff'}; font-weight:900; flex-shrink:0; margin-left:8px;">
                        ${tStats.correct || 0}
                      </span>
                    </div>
                  `;
        }).join('')}
              </div>
            ` : `
              <div style="font-size:10px; color:var(--text-ghost); text-align:center; padding:8px;">
                No team data recorded
              </div>
            `}

          </div>
        `;
      });
    }

    container.innerHTML = html;

    // Clear notification state
    if (STATE.lastChecked) {
      STATE.lastChecked.songOfDay = todayKST;
      saveNotificationState();
    }

  } catch (e) {
    showPageError(container, 'renderSongOfDay');
  }
}

async function submitSongAnswer() {
  const answer = $('sotdAnswer')?.value?.trim();
  const resultEl = $('sotdResult');

  if (!answer) {
    if (resultEl) resultEl.innerHTML = '<span style="color:var(--red-main)">Paste a YouTube URL</span>';
    return;
  }

  if (resultEl) resultEl.innerHTML = '<span style="color:var(--text-muted)">Checking...</span>';

  try {
    const d = await Api.call('submitSongAnswer', {
      agentNo: STATE.agentNo,
      answer,
    }, { dedupe: false, cache: false });

    if (d.correct) {
      const todayKST = getKSTDateString();
      localStorage.setItem(`sotd_answered_${STATE.agentNo}_${todayKST}`, 'true');
      if (STATE.lastChecked) STATE.lastChecked.songOfDay = todayKST;

      if (resultEl) resultEl.innerHTML = `<span style="color:var(--green)">${sanitize(d.message)}</span>`;
      showToast(d.message, 'success');

      // Invalidate SOTD cache and re-render
      Api.invalidate('getSongOfDay');
      Timers.setTimeout('sotd-rerender', renderSongOfDay, 1500);
    } else {
      if (resultEl) resultEl.innerHTML = `<span style="color:var(--red-main)">${sanitize(d.message || d.error)}</span>`;
    }
  } catch (e) {
    if (resultEl) resultEl.innerHTML = `<span style="color:var(--red-main)">${sanitize(e.message)}</span>`;
  }
}


