// ==================== TAB: ALIENS GAME ====================

async function renderAdminAliensTab(container) {
  if (!container) container = $('admin-panel-body');
  if (!container) return;
  container.innerHTML = `<div style="text-align:center;padding:40px;color:var(--text-muted);font-size:12px;">⏳ Loading Aliens status…</div>`;

  let status = null;
  try { status = await Api.call('aliensGetStatus', { agentNo: STATE.agentNo }, { cache: false }); } catch (e) {}

  // Default next Friday 6 PM IST
  const now = new Date();
  const istOffset = 5.5 * 3600000;
  const istNow = new Date(now.getTime() + istOffset);
  const dayOfWeek = istNow.getUTCDay();
  let daysUntilFri = (5 - dayOfWeek + 7) % 7;
  if (daysUntilFri === 0 && istNow.getUTCHours() >= 18) daysUntilFri = 7;
  const nextFri = new Date(istNow);
  nextFri.setUTCDate(nextFri.getUTCDate() + daysUntilFri);
  nextFri.setUTCHours(18, 0, 0, 0); // 6 PM IST = 18:00 in IST clock
  const defaultLocal = new Date(nextFri.getTime() - istOffset);
  const datetimeLocal = defaultLocal.toISOString().slice(0, 16);

  // Current game block
  let currentGameHtml = '';
  if (status?.hasGame) {
    const phaseLabel = {
      waiting: '⏳ Waiting for lobby to open',
      lobby_open: '🛸 LOBBY OPEN — players joining',
      preparing: '⚙️ Preparing — roles being assigned',
      round_reveal: '🎬 Round revealing',
      round_active: '🔓 Round active',
      round_results: '📊 Round results',
      completed: '✅ Completed',
      cancelled: '❌ Cancelled',
    }[status.phase] || status.phase;
    const sched = new Date(status.scheduledFor);
    const lobby = new Date(status.lobbyOpensAt);
    currentGameHtml = `
      <div class="archive-card" style="border-top:3px solid #bf5af2; margin-bottom:24px;">
        <div style="font-size:14px;font-weight:900;color:#bf5af2;font-family:'Orbitron',sans-serif;letter-spacing:1px;margin-bottom:12px;">🛸 CURRENT GAME</div>
        <div style="display:flex;flex-direction:column;gap:8px;font-size:11px;color:var(--text-muted);">
          <div><strong style="color:#fff;">Status:</strong> ${phaseLabel}</div>
          <div><strong style="color:#fff;">Scheduled:</strong> ${sched.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })} IST</div>
          <div><strong style="color:#fff;">Lobby opens:</strong> ${lobby.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })} IST</div>
          <div><strong style="color:#fff;">Players in lobby:</strong> ${status.lobbyCount} / ${status.minPlayers} minimum</div>
          ${status.phase === 'completed' && status.winner ? `<div><strong style="color:#fff;">Winner:</strong> <span style="color:${status.winner==='town'?'var(--green)':'var(--fail)'};text-transform:uppercase;font-weight:900;">${status.winner}</span></div>` : ''}
          ${status.codeBreaksTotal !== undefined ? `<div><strong style="color:#fff;">Code breaks so far:</strong> ${status.codeBreaksTotal}</div>` : ''}
        </div>
        ${['waiting','lobby_open','preparing','round_reveal','round_active','round_results'].includes(status.phase)
          ? `<button onclick="adminCancelAliensGame()" class="btn-outline" style="margin-top:16px;width:100%;border-color:var(--fail);color:var(--fail);padding:10px;font-size:11px;">❌ Cancel This Game</button>`
          : ''}
      </div>`;
  }

  container.innerHTML = `
    ${currentGameHtml}
    <div class="archive-card" style="border-top:3px solid #bf5af2;">
      <div style="font-size:14px;font-weight:900;color:#bf5af2;font-family:'Orbitron',sans-serif;letter-spacing:1px;margin-bottom:12px;">
        📅 SCHEDULE NEXT GAME
      </div>
      <p style="font-size:11px;color:var(--text-muted);margin-bottom:16px;line-height:1.6;">
        Pick when the game should start. Lobby opens automatically 30 minutes before. Default = next Friday 6 PM IST.
      </p>
      <label style="display:block;font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px;">Game Start Time (your local time)</label>
      <input type="datetime-local" id="aliensScheduleInput" value="${datetimeLocal}"
        style="width:100%;background:rgba(255,255,255,0.06);border:1px solid var(--border-subtle);border-radius:6px;padding:10px 12px;color:#fff;font-size:12px;margin-bottom:12px;font-family:var(--font-mono);">
      <div style="font-size:9px;color:var(--text-ghost);margin-bottom:16px;">
        💡 In IST? Next Friday 6 PM IST is pre-filled. Adjust if needed.
      </div>
      <button onclick="adminScheduleAliensGame()" class="btn-red" style="width:100%;padding:12px;font-size:11px;">
        🛸 Schedule Game + Notify Everyone
      </button>
      <div style="margin-top:14px;padding:10px 12px;background:rgba(255,159,10,0.06);border:1px solid rgba(255,159,10,0.3);border-radius:6px;font-size:10px;color:var(--text-muted);line-height:1.6;">
        ⚠️ Scheduling a new game will <strong style="color:#ff9f0a;">cancel any existing lobby/game</strong>. Push notification goes to all agents immediately.
      </div>
    </div>`;
}
window.renderAdminAliensTab = renderAdminAliensTab;

window.adminScheduleAliensGame = async function() {
  const input = document.getElementById('aliensScheduleInput');
  const localStr = input?.value;
  if (!localStr) { showToast('Pick a date/time', 'error'); return; }
  const scheduledFor = new Date(localStr).toISOString();
  if (new Date(scheduledFor).getTime() < Date.now() + 30 * 60000) {
    showToast('Game must be scheduled at least 30 min in the future (lobby needs time to open)', 'error');
    return;
  }
  if (!confirm(`Schedule Aliens game for ${new Date(scheduledFor).toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })} IST?\n\nThis will cancel any existing game and notify all agents.`)) return;
  Loading.show();
  try {
    const res = await Api.call('aliensCreateGame', { adminKey: 'BTSSPYADMIN2024', scheduledFor }, { cache: false, dedupe: false });
    Loading.hide();
    if (res.success) {
      showToast(res.message || 'Game scheduled', 'success');
      renderAdminAliensTab($('admin-panel-body'));
    } else {
      showToast(res.error || 'Failed to schedule', 'error');
    }
  } catch (e) {
    Loading.hide();
    showToast(e.message || 'Network error', 'error');
  }
};

window.adminCancelAliensGame = async function() {
  if (!confirm('Cancel the current Aliens game? All agents will be notified.')) return;
  Loading.show();
  try {
    const res = await Api.call('aliensCancelGame', { adminKey: 'BTSSPYADMIN2024' }, { cache: false, dedupe: false });
    Loading.hide();
    if (res.success) {
      showToast('Game cancelled', 'success');
      renderAdminAliensTab($('admin-panel-body'));
    } else {
      showToast(res.error || 'Failed to cancel', 'error');
    }
  } catch (e) {
    Loading.hide();
    showToast(e.message || 'Network error', 'error');
  }
};

window.adminApproveDailyVote = async function(teamName) {
  if (!confirm(`Award 30 XP to ${teamName} for today's voting mission?`)) return;
  Loading.show();
  try {
    const res = await Api.call('updateTeamStatus', {
      team: teamName,
      field: 'addManualXP',
      value: 30,
      sessionToken: STATE.adminSession
    }, { dedupe: false, cache: false });
    if (res.success) {
      showToast(`✅ 30 XP awarded to ${teamName}!`, 'success');
      Api.invalidate('getWeeklySummary');
    } else {
      showToast(`❌ Failed: ${res.error || 'Backend missing manual XP handler'}`, 'error');
    }
  } catch (e) {
    showToast('❌ System Error: ' + e.message, 'error');
  } finally {
    Loading.hide();
  }
};

