async function renderTraineesPage() {
  const container = $('traineesContent');
  if (!container) return;
  container.innerHTML = `<div style="text-align:center;padding:32px;color:var(--text-muted);font-size:12px;">Loading...</div>`;

  try {
    const d = await Api.call('getTraineeOverview', { agentNo: STATE.agentNo }, { dedupe: false, cache: false });
    if (!d?.success) throw new Error(d?.error || 'Failed to load');
    const raw = d.trainees || [];

    if (!raw.length) {
      container.innerHTML = `<div class="glass-card" style="text-align:center;padding:48px 24px;">
        <div style="font-size:40px;margin-bottom:12px;">🎓</div>
        <div style="font-size:13px;font-weight:900;color:#fff;">No Active Trainees</div>
        <div style="font-size:11px;color:var(--text-ghost);margin-top:6px;">All agents fully promoted 💜</div>
      </div>`;
      return;
    }

    // ── helpers ──────────────────────────────────────────────────────────
    const TEAM_COLORS = {
      Mono:'#10b981', Muse:'#ec4899', HopeWorld:'#f59e0b',
      Happy:'#eab308', Layover:'#3b82f6', 'D-Day':'#ef4444',
      Friends:'#7C5CBF',
    };
    const tc = t => TEAM_COLORS[t.team] || '#7c3aed';

    const noStr  = t => (t.arirangWeekTotal||0)===0 && (t.sideWeekTotal||0)===0;
    const streamedToday = t => (t.arirangToday?.done||0)>0 || (t.sideToday?.done||0)>0;
    const status = t => {
      if (t.readyToPromote)                          return { dot:'✅', label:'Ready!',          color:'var(--green)' };
      if (noStr(t))                                  return { dot:'🔴', label:'No Streams',       color:'var(--fail)' };
      if ((t.totalXP||0)<10 || t.daysRemaining<=1 || !streamedToday(t))
                                                     return { dot:'🟡', label:'Needs Attention', color:'var(--courage-amber)' };
      return                                                { dot:'🟢', label:'On Track',         color:'var(--green)' };
    };

    // ── enrich + sort by REAL XP (same formula as all agents) ───────────
    const trainees = raw.map(t => ({ ...t, _status: status(t), _noStr: noStr(t) }))
                        .sort((a,b) => (b.totalXP||0) - (a.totalXP||0));

    // ── header stats ────────────────────────────────────────────────────
    const teamsRep  = new Set(trainees.map(t=>t.team)).size;
    const avgXP     = trainees.length ? Math.round(trainees.reduce((s,t)=>s+(t.totalXP||0),0)/trainees.length) : 0;
    const needsHelp = trainees.filter(t => t._status.dot==='🔴'||t._status.dot==='🟡');

    // ── SVG circle meter ────────────────────────────────────────────────
    const meter = (t, color) => {
      const pct  = Math.min(100, Math.round(((t.daysTrained||0)/7)*100));
      const r    = 16, circ = 2*Math.PI*r;
      const dash = circ*(pct/100);
      return `<svg width="40" height="40" viewBox="0 0 40 40" style="flex-shrink:0;">
        <circle cx="20" cy="20" r="${r}" fill="none" stroke="rgba(255,255,255,0.08)" stroke-width="3"/>
        <circle cx="20" cy="20" r="${r}" fill="none" stroke="${color}" stroke-width="3"
          stroke-dasharray="${dash} ${circ-dash}" stroke-linecap="round"
          transform="rotate(-90 20 20)"/>
        <text x="20" y="20" text-anchor="middle" dominant-baseline="middle"
          fill="#fff" font-size="7" font-weight="900" font-family="sans-serif">${t.daysTrained||0}/7</text>
      </svg>`;
    };

    // ── 7-day grid dots ──────────────────────────────────────────────────
    const gridDots = (grid) => (grid || []).map(g => {
      if (g.preJoin)  return `<span title="${g.date}: before joining" style="color:rgba(255,255,255,0.12);">·</span>`;
      if (g.future)   return `<span title="${g.date}: upcoming" style="color:rgba(255,255,255,0.18);">○</span>`;
      if (g.complete) return `<span title="${g.date}: full daily mission done (${g.done}/${g.total})" style="color:var(--green);">●</span>`;
      if (g.partial)  return `<span title="${g.date}: partial (${g.done}/${g.total})" style="color:var(--courage-amber);">◐</span>`;
      return `<span title="${g.date}: none (0/${g.total})" style="color:rgba(255,255,255,0.28);">○</span>`;
    }).join('');

    // ── one daily-mission row (Today X/Y + 7-day grid) ───────────────────
    const missionRow = (emoji, label, today, grid) => {
      const d = today?.done || 0, tot = today?.total || 0;
      const tColor = d >= tot ? 'var(--green)' : d > 0 ? 'var(--courage-amber)' : 'var(--fail)';
      return `
      <div style="display:flex;align-items:center;gap:8px;margin-top:6px;">
        <span style="flex:1;min-width:0;font-size:9px;color:var(--text-muted);font-weight:700;white-space:nowrap;">${emoji} ${label}</span>
        <span style="font-size:9px;font-weight:800;color:${tColor};white-space:nowrap;">Today ${d}/${tot}</span>
        <span style="font-size:11px;letter-spacing:3px;white-space:nowrap;">${gridDots(grid)}</span>
      </div>`;
    };

    // ── single card renderer ─────────────────────────────────────────────
    const card = (t, rank) => {
      const color = tc(t);
      const st    = t._status;
      return `
      <div class="glass-card" style="padding:12px 14px;border-left:3px solid ${color};margin-bottom:8px;">
        <div style="display:flex;align-items:center;gap:10px;">
          ${meter(t, color)}
          <div style="flex:1;min-width:0;">
            <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
              <span style="font-size:9px;color:var(--text-ghost);font-weight:700;">#${rank}</span>
              <span style="font-size:12px;font-weight:900;color:#fff;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${sanitize(t.name)}</span>
              <span style="font-size:9px;font-weight:800;color:${st.color};white-space:nowrap;">${st.dot} ${st.label}</span>
            </div>
            <div style="font-size:9px;color:var(--text-ghost);margin-top:2px;">
              <span style="color:${color};font-weight:700;">${sanitize(t.team)}</span>
              · ${t.agentNo}
              · ${t.daysRemaining>0?`${t.daysRemaining}d left`:'Ready'}
            </div>
          </div>
          <span style="background:rgba(167,139,250,0.12);border:1px solid rgba(167,139,250,0.3);color:${(t.totalXP||0)>0?'#a78bfa':'var(--fail)'};
            padding:3px 9px;border-radius:20px;font-size:9px;font-weight:900;white-space:nowrap;flex-shrink:0;">⭐ ${t.totalXP||0} XP</span>
        </div>

        <!-- Daily missions — mirrors the agent system -->
        <div style="margin-top:8px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.05);">
          ${missionRow('🔁', 'Arirang 2X',    t.arirangToday, t.arirangGrid)}
          ${missionRow('🛡️', 'Side Missions', t.sideToday,    t.sideGrid)}
        </div>

        ${t._noStr ? `<div style="margin-top:8px;font-size:9px;color:var(--fail);background:rgba(239,68,68,0.08);
          border:1px solid rgba(239,68,68,0.25);border-radius:6px;padding:5px 8px;">⚠️ No Last.fm streams this week — check their account is linked</div>` : ''}
      </div>`;
    };

    // ── filter state ────────────────────────────────────────────────────
    window._traineeFilter = window._traineeFilter || 'all';
    const setFilter = f => { window._traineeFilter = f; renderTraineesPage(); };

    const filtered = window._traineeFilter === 'needs'   ? trainees.filter(t=>t._status.dot==='🔴'||t._status.dot==='🟡')
                   : window._traineeFilter === 'soon'    ? trainees.filter(t=>t.daysRemaining<=2)
                   : window._traineeFilter === 'nostr'   ? trainees.filter(t=>t._noStr)
                   : trainees;

    const tabBtn = (f, label, count) => {
      const active = window._traineeFilter === f;
      return `<button onclick="window._traineeFilter='${f}';renderTraineesPage()"
        style="padding:6px 12px;border-radius:20px;font-size:10px;font-weight:800;cursor:pointer;border:1px solid;
        background:${active?'rgba(124,58,237,0.25)':'transparent'};
        border-color:${active?'rgba(139,92,246,0.6)':'rgba(255,255,255,0.12)'};
        color:${active?'#a78bfa':'var(--text-muted)'};
        transition:all 0.15s;">${label}${count!=null?` <span style="opacity:0.7;">(${count})</span>`:''}
      </button>`;
    };

    // ── render ───────────────────────────────────────────────────────────
    container.innerHTML = `
      <!-- Header -->
      <div class="glass-card" style="padding:14px 16px;margin-bottom:14px;border-left:3px solid #a78bfa;">
        <div style="font-size:10px;font-weight:900;color:#a78bfa;letter-spacing:2px;text-transform:uppercase;margin-bottom:8px;">🎓 Training Division</div>
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;text-align:center;">
          <div>
            <div style="font-size:20px;font-weight:900;color:#fff;">${trainees.length}</div>
            <div style="font-size:8px;color:var(--text-ghost);text-transform:uppercase;letter-spacing:1px;">Active</div>
          </div>
          <div>
            <div style="font-size:20px;font-weight:900;color:#fff;">${teamsRep}</div>
            <div style="font-size:8px;color:var(--text-ghost);text-transform:uppercase;letter-spacing:1px;">Teams</div>
          </div>
          <div>
            <div style="font-size:20px;font-weight:900;color:#a78bfa;">${avgXP}</div>
            <div style="font-size:8px;color:var(--text-ghost);text-transform:uppercase;letter-spacing:1px;">Avg XP</div>
          </div>
        </div>

        <!-- How to read this page (collapsible) -->
        <details style="margin-top:12px;border-top:1px solid rgba(255,255,255,0.07);padding-top:10px;">
          <summary style="font-size:9px;color:#a78bfa;font-weight:800;cursor:pointer;letter-spacing:1px;text-transform:uppercase;outline:none;">
            ℹ️ How to read this page
          </summary>
          <div style="font-size:9px;color:var(--text-muted);line-height:1.8;margin-top:8px;">
            <div style="margin-bottom:6px;color:var(--text-secondary);font-weight:700;">Status (next to each name):</div>
            <div>🟢 <strong>On Track</strong> — streamed today, healthy XP</div>
            <div>🟡 <strong>Needs Attention</strong> — low XP, promoting in ≤1 day, or hasn't streamed today</div>
            <div>🔴 <strong>No Streams</strong> — zero plays all week, likely Last.fm not linked</div>
            <div>✅ <strong>Ready</strong> — 7 days done, auto-promotes on next sync</div>
            <div style="margin:8px 0 6px;color:var(--text-secondary);font-weight:700;">Daily missions (same as agents):</div>
            <div>🔁 <strong>Arirang 2X</strong> — stream each of the 14 album tracks 2× <em>per day</em></div>
            <div>🛡️ <strong>Side Missions</strong> — stream each of the 4 survival tracks 1× <em>per day</em></div>
            <div><strong>Today X/Y</strong> = tracks done so far today · grid = last 7 days:</div>
            <div style="margin-left:4px;"><span style="color:var(--green);">●</span> full day · <span style="color:var(--courage-amber);">◐</span> partial · <span style="color:rgba(255,255,255,0.3);">○</span> missed/upcoming · <span style="color:rgba(255,255,255,0.2);">·</span> pre-join</div>
            <div>⭐ <strong>XP</strong> — same formula as every agent (streams ÷ 10)</div>
            <div>◔ <strong>Ring</strong> — days into the 7-day training period</div>
            <div style="margin-top:8px;color:var(--text-ghost);font-style:italic;">
              Trainees are exempt — they can't make a team fail — but their streams still count toward team goals. Use this to spot who needs a nudge 💜
            </div>
          </div>
        </details>
      </div>

      <!-- Needs Attention -->
      ${needsHelp.length ? `
      <div style="margin-bottom:14px;">
        <div style="font-size:10px;font-weight:900;color:var(--courage-amber);letter-spacing:2px;text-transform:uppercase;margin-bottom:8px;">
          🚨 Needs Attention (${needsHelp.length})
        </div>
        ${needsHelp.map((t,i) => `
          <div style="display:flex;align-items:center;justify-content:space-between;gap:8px;
            padding:8px 12px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.2);
            border-left:3px solid ${tc(t)};border-radius:8px;margin-bottom:6px;">
            <div>
              <span style="font-size:11px;font-weight:900;color:#fff;">${sanitize(t.name)}</span>
              <span style="font-size:9px;color:var(--text-ghost);margin-left:6px;">${t.agentNo}</span>
            </div>
            <div style="text-align:right;">
              <div style="font-size:9px;color:${t._status.color};font-weight:800;">${t._status.dot} ${t._status.label}</div>
              <div style="font-size:8px;color:var(--text-ghost);">${t.totalXP||0} XP · ${t.daysRemaining}d left</div>
            </div>
          </div>`).join('')}
      </div>` : ''}

      <!-- Filter tabs -->
      <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:12px;">
        ${tabBtn('all','All',trainees.length)}
        ${tabBtn('needs','Needs Help',needsHelp.length)}
        ${tabBtn('soon','Promoting Soon',trainees.filter(t=>t.daysRemaining<=2).length)}
        ${tabBtn('nostr','No Streams',trainees.filter(t=>t._noStr).length)}
      </div>

      <!-- Cards -->
      ${filtered.length
        ? filtered.map((t,i) => card(t, trainees.indexOf(t)+1)).join('')
        : `<div style="text-align:center;padding:24px;color:var(--text-ghost);font-size:11px;">No trainees in this filter.</div>`
      }

      <div style="text-align:center;font-size:9px;color:var(--text-ghost);margin-top:12px;padding-top:12px;border-top:1px solid rgba(255,255,255,0.05);">
        Promotion auto-runs after 7 days · Streams from Last.fm · ${d.week||''}
      </div>`;

  } catch (e) {
    container.innerHTML = `<div class="glass-card" style="border-left:3px solid var(--fail);padding:20px;">
      <div style="color:var(--fail);font-size:12px;font-weight:800;">❌ ${e.message}</div>
      <button onclick="renderTraineesPage()" class="btn-outline" style="margin-top:12px;font-size:10px;">↺ Retry</button>
    </div>`;
  }
}


// =============================================

async function renderOperatives() {
  const container = $('operativesContent');
  if (!container) return;

  showPageLoading(container);

  try {
    // 1. Fetch Data
    const d = await Api.call('getOperativeDatabase', { week: STATE.week }, { cache: true, ttl: 60000 });
    const agents = d.agents || [];
    const myTeam = STATE.data?.agent?.profile?.team;

    // 2. Group by Team & Status
    const byTeam = {};
    Object.keys(CONFIG.TEAMS).forEach(t => byTeam[t] = { active: [], leave: [], trainee: [] });

    agents.forEach(a => {
      const t = a.team || 'Unknown';
      if (!byTeam[t]) byTeam[t] = { active: [], leave: [], trainee: [] };
      if (a.onLeave) byTeam[t].leave.push(a);
      else           byTeam[t].active.push(a); // trainees appear in active list with 🎓 icon
    });

    // 3. Sort Alphabetically
    Object.values(byTeam).forEach(data => {
      data.active.sort((a, b) => (a.name || '').localeCompare(b.name || ''));
      data.leave.sort((a, b) => (a.name || '').localeCompare(b.name || ''));
    });

    let grandTotalActive = 0;
    let grandTotalLeave = 0;

    // 4. Build Header & Search
    let html = `
            <div style="margin-bottom:20px; position:relative;">
                <span style="position:absolute; left:14px; top:50%; transform:translateY(-50%); font-size:14px; pointer-events:none;">🔍</span>
                <input type="text" id="opSearch" oninput="window.filterOperativesModern(this.value)"
                    placeholder="Search agent dossiers..." class="input-field"
                    style="padding-left:40px;">
            </div>

            <div class="glass-card" style="padding:16px; margin-bottom:20px; border-left:3px solid var(--wave-foam); display:flex; align-items:center; gap:12px;">
                <span style="font-size:24px;">💡</span>
                <span style="font-size:11px; color:var(--text-secondary); line-height:1.5;">
                    <strong style="color:var(--wave-foam);">Attendance Helpers:</strong> Tap the circle next to an agent's name to mark them present today. Team stats update in real-time.
                </span>
            </div>

            <div id="opList" style="display:flex; flex-direction:column; gap:20px;">
        `;

    // 5. Render Team Cards
    for (const [team, data] of Object.entries(byTeam)) {
      if (data.active.length === 0 && data.leave.length === 0 && data.trainee.length === 0) continue;

      grandTotalActive += data.active.length;
      grandTotalLeave += data.leave.length;

      const isMyTeam = team === myTeam;
      const tColor = teamColor(team);
      const teamIdClean = team.replace(/\s+/g, '');
      const totalAgents = data.active.length + data.leave.length + data.trainee.length;
      const isDissolvedTeam = team === 'Team Muse' || team === 'Team Layover';

      html += `
                <div class="archive-card team-op-section" style="border-top: 3px solid ${tColor}; padding:0; overflow:hidden;${isDissolvedTeam ? 'opacity:0.4;filter:grayscale(0.6);' : ''}" data-team="${team}">

                    <!-- TEAM HEADER (Collapsible) -->
                    <div style="padding:16px; background:linear-gradient(135deg, ${tColor}11, transparent); display:flex; align-items:center; gap:12px; cursor:pointer;" onclick="toggleNavGroup(this)">
                        <div class="battle-pfp-mid" style="border-color:${tColor}; margin:0; width:40px; height:40px;">
                            <img src="${teamPfp(team)}" alt="${team}">
                        </div>
                        <div style="flex:1;">
                            <div style="font-family:var(--font-display); font-size:14px; font-weight:800; color:${tColor}; letter-spacing:1px; text-transform:uppercase; display:flex; align-items:center; gap:8px; flex-wrap:wrap;">
                                ${team.replace('Team ', '')}
                                ${isDissolvedTeam ? '<span style="font-size:7px;font-weight:900;letter-spacing:1.5px;color:rgba(255,255,255,0.5);border:1px solid rgba(255,255,255,0.2);padding:2px 6px;border-radius:4px;">DISSOLVED</span>' : ''}
                                ${isMyTeam ? '<span style="font-size:8px; color:#fff; background:var(--red-core); padding:2px 6px; border-radius:4px; vertical-align:middle;">YOUR SQUAD</span>' : ''}
                            </div>
                            <div style="font-size:10px; color:var(--text-muted); font-family:var(--font-mono); margin-top:4px;">
                                ${totalAgents} TOTAL • ${data.active.filter(a => !a.isTrainee).length} ACTIVE • ${data.leave.length} GHOST${data.active.filter(a => a.isTrainee).length ? ` • ${data.active.filter(a => a.isTrainee).length} 🎓` : ''}
                            </div>
                        </div>
                        <div class="nav-chevron" style="font-size:14px; color:var(--text-muted); transition:transform 0.3s;">▼</div>
                    </div>

                    <!-- TEAM BODY -->
                    <div class="nav-group-body open" style="padding:0 16px 16px;">
                        
                        <!-- Progress Bar -->
                        <div style="background:rgba(0,0,0,0.3); border:1px solid var(--border-subtle); border-radius:8px; padding:12px; margin-top:16px; margin-bottom:16px;">
                            <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:6px;">
                                <span style="font-size:10px; font-weight:800; color:var(--text-ghost); text-transform:uppercase; letter-spacing:1px;">Today's Presence</span>
                                <span style="font-family:var(--font-mono); font-size:12px; font-weight:900; color:#fff;">
                                    <span id="present-${teamIdClean}">0</span> / <span id="active-${teamIdClean}">${data.active.length}</span>
                                    <span id="percent-${teamIdClean}" style="color:var(--text-muted); margin-left:6px; font-size:10px;">(0%)</span>
                                </span>
                            </div>
                            <div class="pbar" style="height:6px; background:rgba(255,255,255,0.05);">
                                <div class="pfill" id="bar-${teamIdClean}" style="width:0%; background:${tColor}; box-shadow:0 0 10px ${tColor}66;"></div>
                            </div>
                        </div>

                        <!-- Active List -->
                        ${data.active.length > 0 ? `
                            <div style="font-size:10px; font-weight:800; color:var(--green); text-transform:uppercase; letter-spacing:2px; margin-bottom:8px; padding-left:4px;">🟢 Active Operatives</div>
                            <div style="display:flex; flex-direction:column; gap:4px; margin-bottom:16px;">
                                ${data.active.map(a => renderAgentRowModern(a, false, teamIdClean, !!a.isTrainee)).join('')}
                            </div>
                        ` : ''}

                        <!-- Leave List -->
                        ${data.leave.length > 0 ? `
                            <div style="font-size:10px; font-weight:800; color:var(--courage-amber); text-transform:uppercase; letter-spacing:2px; margin-bottom:8px; padding-left:4px;">💤 Ghost Protocol (Leave)</div>
                            <div style="display:flex; flex-direction:column; gap:4px;">
                                ${data.leave.map(a => renderAgentRowModern(a, true, teamIdClean)).join('')}
                            </div>
                        ` : ''}

                    </div>
                </div>
            `;
    }

    // 6. Overall Summary Footer
    html += `
            </div><!-- end opList -->

            <!-- OVERALL STATS -->
            <div class="glass-card" style="margin-top:24px; padding:20px; border-top:3px solid var(--gold-core);">
                <div style="display:flex; align-items:center; gap:10px; margin-bottom:16px;">
                    <span style="font-size:20px;">📋</span>
                    <div style="font-size:12px; font-weight:900; color:var(--gold-core); text-transform:uppercase; letter-spacing:2px;">Overall Attendance</div>
                </div>
                
                <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px;">
                    <span style="font-size:10px; color:var(--text-muted); text-transform:uppercase;">Network Total</span>
                    <span style="font-family:var(--font-mono); font-size:14px; font-weight:900;">
                        <span id="overall-present" style="color:var(--green);">0</span> / 
                        <span id="overall-active" style="color:#fff;">${grandTotalActive}</span>
                        <span id="overall-percent" style="color:var(--text-muted); font-size:11px; margin-left:4px;">(0%)</span>
                    </span>
                </div>
                <div class="pbar" style="height:8px; margin-bottom:16px; background:rgba(255,255,255,0.05);">
                    <div class="pfill gold" id="overall-bar" style="width:0%;"></div>
                </div>

                <div class="grid-3" style="text-align:center;">
                    <div style="padding:10px; background:rgba(255,255,255,0.02); border-radius:8px; border:1px solid var(--border-subtle);">
                        <div style="font-family:var(--font-mono); font-size:16px; font-weight:900; color:#fff;">${grandTotalActive + grandTotalLeave}</div>
                        <div style="font-size:8px; color:var(--text-muted); text-transform:uppercase; margin-top:2px;">Total Force</div>
                    </div>
                    <div style="padding:10px; background:rgba(255,255,255,0.02); border-radius:8px; border:1px solid var(--border-subtle);">
                        <div style="font-family:var(--font-mono); font-size:16px; font-weight:900; color:var(--green);">${grandTotalActive}</div>
                        <div style="font-size:8px; color:var(--text-muted); text-transform:uppercase; margin-top:2px;">Active</div>
                    </div>
                    <div style="padding:10px; background:rgba(255,255,255,0.02); border-radius:8px; border:1px solid var(--border-subtle);">
                        <div style="font-family:var(--font-mono); font-size:16px; font-weight:900; color:var(--courage-amber);">${grandTotalLeave}</div>
                        <div style="font-size:8px; color:var(--text-muted); text-transform:uppercase; margin-top:2px;">On Leave</div>
                    </div>
                </div>
            </div>

            <!-- POLICE LOGIN SECTION -->
            <div id="police-section" style="margin-top:24px;">
                <div class="glass-card" onclick="window.showPoliceLoginModern()" style="cursor:pointer; padding:16px; display:flex; justify-content:space-between; align-items:center; border-left:3px solid var(--red-core); transition:border-color 0.3s;" onmouseover="this.style.borderColor='var(--red-mid)'" onmouseout="this.style.borderColor='var(--red-core)'">
                    <div style="display:flex; align-items:center; gap:12px;">
                        <span style="font-size:20px;">👮</span>
                        <span style="font-size:12px; font-weight:900; color:#fff; text-transform:uppercase; letter-spacing:2px;">Police Verification</span>
                    </div>
                    <span style="color:var(--text-muted); font-size:10px;">Tap to access ▶</span>
                </div>
            </div>

            <!-- POLICE MODAL (Inline) -->
            <div id="police-login-modal" style="display:none; margin-top:24px;">
                <div class="glass-card" style="padding:20px; border-top:3px solid var(--red-core);">
                    <div style="display:flex; align-items:center; gap:10px; margin-bottom:16px;">
                        <span style="font-size:20px;">🔐</span>
                        <span style="font-size:12px; font-weight:900; color:var(--red-core); text-transform:uppercase; letter-spacing:2px;">Enter Police Code</span>
                    </div>
                    <div style="display:flex; gap:8px;">
                        <input type="password" id="police-password" class="input-field" placeholder="Enter passcode..." 
                            onkeydown="if(event.key==='Enter') window.verifyPoliceAccessModern()">
                        <button onclick="window.verifyPoliceAccessModern()" class="btn-red" style="width:auto; padding:10px 24px;">VERIFY</button>
                    </div>
                </div>
            </div>

            <div id="police-lastfm-container" style="display:none; margin-top:24px;"></div>
        `;

    container.innerHTML = html;

    // Trigger calculations & cleanup
    window.cleanupOldCheckmarks();
    window.updateAllAttendanceStatsModern();

  } catch (e) {
    console.error('renderOperatives error:', e);
    showPageError(container, 'renderOperatives');
  }
}

// ── Helper: Render Individual Row ──
function renderAgentRowModern(agent, isLeave, teamIdClean, isTrainee = false) {
  const today = getKSTDateString();
  const agentNo = agent.agentNo || 'N/A';
  const storageKey = `helper_check_${agentNo}_${today}`;
  const isChecked = localStorage.getItem(storageKey) === 'true';

  let displayName = agent.name ? sanitize(agent.name) : 'Unknown Agent';
  if (displayName.toUpperCase().startsWith('AGENT') || !agent.name) displayName = 'Classified Agent';

  const statusBadge = isTrainee
    ? `<span style="font-size:8px; font-weight:800; padding:4px 8px; background:rgba(245,158,11,0.1); color:#f59e0b; border-radius:12px; border:1px solid rgba(245,158,11,0.3);">🎓 NEW</span>`
    : isLeave
      ? `<span style="font-size:8px; font-weight:800; padding:4px 8px; background:rgba(255,149,0,0.1); color:var(--courage-amber); border-radius:12px; border:1px solid rgba(255,149,0,0.3);">GHOST</span>`
      : (agent.attendanceSubmitted
        ? `<span style="font-size:8px; font-weight:800; padding:4px 8px; background:rgba(0,255,102,0.1); color:var(--green); border-radius:12px; border:1px solid rgba(0,255,102,0.3);">SUBMITTED</span>`
        : ``);

  const rowOpacity = (isLeave || isTrainee) ? 'opacity:0.65;' : '';

  return `
        <div class="op-row-modern ${isLeave ? 'on-leave' : ''} ${isTrainee ? 'is-trainee' : ''} ${isChecked ? 'checked' : ''}"
             data-agent="${agentNo}" data-team-ref="${teamIdClean}"
             data-search="${(agent.name || '').toLowerCase()} ${agentNo.toLowerCase()} ${isTrainee ? 'trainee' : ''}"
             style="display:flex; align-items:center; gap:12px; padding:10px 12px; background:rgba(255,255,255,0.02); border:1px solid ${isTrainee ? 'rgba(245,158,11,0.2)' : 'var(--border-subtle)'}; border-radius:8px; transition:all 0.2s; ${rowOpacity}">

            ${isTrainee ? `
            <div style="width:24px; height:24px; border-radius:50%; border:2px dashed #f59e0b; display:flex; align-items:center; justify-content:center; flex-shrink:0;">
                <span style="font-size:12px;">🎓</span>
            </div>
            ` : !isLeave ? `
            <div class="helper-check-wrapper" onclick="window.toggleHelperCheckModern(event, this, '${agentNo}', '${teamIdClean}')"
                 style="width:24px; height:24px; border-radius:50%; border:2px solid ${isChecked ? 'var(--green)' : 'var(--text-muted)'}; background:${isChecked ? 'rgba(0,255,102,0.1)' : 'transparent'}; display:flex; align-items:center; justify-content:center; cursor:pointer; flex-shrink:0; transition:all 0.2s;">
                <span class="helper-checkbox" style="color:${isChecked ? 'var(--green)' : 'transparent'}; font-size:14px; font-weight:900;">${isChecked ? '✓' : ''}</span>
            </div>
            ` : `
            <div style="width:24px; height:24px; border-radius:50%; border:2px dashed var(--courage-amber); opacity:0.5; display:flex; align-items:center; justify-content:center; flex-shrink:0;">
                <span style="font-size:10px;">💤</span>
            </div>
            `}

            <div style="flex:1; min-width:0;">
                <div style="font-size:13px; font-weight:700; color:${(isLeave || isTrainee) ? 'var(--text-muted)' : '#fff'}; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;">
                    ${isTrainee ? '🎓 ' : ''}${displayName}
                </div>
                <div style="font-size:9px; color:var(--text-ghost); font-family:var(--font-mono); margin-top:2px;">
                    ID: ${agentNo}
                </div>
            </div>

            <div style="flex-shrink:0;">
                ${statusBadge}
            </div>
        </div>
    `;
}

// ── Helper: Checkbox Toggle ──
window.toggleHelperCheckModern = function (event, wrapper, agentNo, teamId) {
  event.stopPropagation();
  const today = getKSTDateString();
  const storageKey = `helper_check_${agentNo}_${today}`;

  const row = wrapper.closest('.op-row-modern');
  const checkbox = wrapper.querySelector('.helper-checkbox');
  if (!row || !checkbox) return;

  const isNowChecked = !row.classList.contains('checked');

  if (isNowChecked) {
    row.classList.add('checked');
    wrapper.style.borderColor = 'var(--green)';
    wrapper.style.background = 'rgba(0,255,102,0.1)';
    checkbox.style.color = 'var(--green)';
    checkbox.textContent = '✓';
    localStorage.setItem(storageKey, 'true');
    if (navigator.vibrate) navigator.vibrate(10);
    row.style.transform = 'scale(1.02)';
    setTimeout(() => { row.style.transform = ''; }, 150);
  } else {
    row.classList.remove('checked');
    wrapper.style.borderColor = 'var(--text-muted)';
    wrapper.style.background = 'transparent';
    checkbox.style.color = 'transparent';
    checkbox.textContent = '';
    localStorage.removeItem(storageKey);
  }

  window.updateTeamStatsModern(teamId);
  window.updateAllAttendanceStatsModern();
};

// ── Helper: Calculate Stats ──
window.updateTeamStatsModern = function (teamId) {
  const activeItems = document.querySelectorAll(`.op-row-modern[data-team-ref="${teamId}"]:not(.on-leave)`);
  const totalActive = activeItems.length;
  let presentCount = 0;

  activeItems.forEach(item => {
    if (item.classList.contains('checked')) presentCount++;
  });

  const percentage = totalActive > 0 ? Math.round((presentCount / totalActive) * 100) : 0;

  const presentEl = $(`present-${teamId}`);
  const barEl = $(`bar-${teamId}`);
  const percentEl = $(`percent-${teamId}`);

  if (presentEl) presentEl.textContent = presentCount;
  if (barEl) barEl.style.width = `${percentage}%`;
  if (percentEl) {
    percentEl.textContent = `(${percentage}%)`;
    if (percentage >= 80) percentEl.style.color = 'var(--green)';
    else if (percentage >= 50) percentEl.style.color = 'var(--courage-amber)';
    else percentEl.style.color = 'var(--fail)';
  }

  return { present: presentCount, total: totalActive };
};

window.updateAllAttendanceStatsModern = function () {
  const teamSections = document.querySelectorAll('.team-op-section');
  let overallPresent = 0;
  let overallActive = 0;

  teamSections.forEach(section => {
    const teamName = section.getAttribute('data-team');
    const teamIdClean = teamName.replace(/\s+/g, '');
    const stats = window.updateTeamStatsModern(teamIdClean);
    overallPresent += stats.present;
    overallActive += stats.total;
  });

  const percentage = overallActive > 0 ? Math.round((overallPresent / overallActive) * 100) : 0;

  const presentEl = $('overall-present');
  const barEl = $('overall-bar');
  const percentEl = $('overall-percent');

  if (presentEl) presentEl.textContent = overallPresent;
  if (barEl) barEl.style.width = `${percentage}%`;
  if (percentEl) {
    percentEl.textContent = `(${percentage}%)`;
    if (percentage >= 80) percentEl.style.color = 'var(--green)';
    else if (percentage >= 50) percentEl.style.color = 'var(--courage-amber)';
    else percentEl.style.color = 'var(--fail)';
  }
};

// ── Helper: Cleanup Old Data ──
window.cleanupOldCheckmarks = function () {
  const today = getKSTDateString();
  const keysToRemove = [];
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (key && key.startsWith('helper_check_') && !key.endsWith(today)) {
      keysToRemove.push(key);
    }
  }
  keysToRemove.forEach(key => localStorage.removeItem(key));
};

// ── Helper: Search Filter ──
window.filterOperativesModern = function (query) {
  const q = (query || '').toLowerCase().trim();
  const rows = document.querySelectorAll('.op-row-modern');

  rows.forEach(row => {
    const name = row.getAttribute('data-search') || '';
    row.style.display = name.includes(q) ? 'flex' : 'none';
  });

  // Hide empty teams
  const teamCards = document.querySelectorAll('.team-op-section');
  teamCards.forEach(card => {
    const hasVisible = Array.from(card.querySelectorAll('.op-row-modern')).some(r => r.style.display !== 'none');
    card.style.display = hasVisible ? 'block' : 'none';

    // Auto-expand if searching
    const body = card.querySelector('.nav-group-body');
    const header = card.querySelector('[onclick*="toggleNavGroup"]');
    if (q.length > 0 && hasVisible) {
      if (body) {
        body.classList.add('open');
        body.style.maxHeight = '6000px';
      }
      if (header) header.classList.add('open');
    }
  });
};


