// ══════════════════════════════════════════════════════════════════════
// GAME 9 — ALIENS (Friday Mafia Game)
// ══════════════════════════════════════════════════════════════════════

let _aliensPoll = null;
let _aliensState = null;

async function renderAliens() {
  const container = $('aliensContent');
  if (!container) return;
  container.innerHTML = `
    <div class="glass-card" style="padding:24px;text-align:center;border:1px solid var(--border-subtle);background:rgba(255,255,255,0.02);">
      <div style="font-size:36px;margin-bottom:10px;">🛸</div>
      <div style="font-size:12px;font-weight:900;color:var(--text-primary);margin-bottom:6px;">Not Live Yet</div>
      <div style="font-size:10px;color:var(--text-muted);line-height:1.7;">Aliens: Rescue Mission is offline right now.<br>HQ will broadcast when the next operation launches 📡</div>
    </div>`;
  return;
  try {
    const d = await Api.call('aliensGetStatus', { agentNo: STATE.agentNo }, { cache: false });
    if (!d.success || !d.hasGame) {
      // No game scheduled — show "next Friday" placeholder
      container.innerHTML = _aliensRenderNoGame();
      if (_aliensPoll) { clearInterval(_aliensPoll); _aliensPoll = null; }
      return;
    }
    _aliensState = d;
    container.innerHTML = _aliensRenderByPhase(d);
    // Poll every 5 seconds while game is active
    if (!_aliensPoll && ['lobby_open','preparing','round_reveal','round_active','round_results'].includes(d.phase)) {
      _aliensPoll = setInterval(() => renderAliens(), 5000);
    }
    if (_aliensPoll && ['completed','cancelled','waiting'].includes(d.phase)) {
      clearInterval(_aliensPoll); _aliensPoll = null;
    }
  } catch (e) {
    container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">Failed to load Aliens. <button onclick="renderAliens()" class="btn-outline" style="margin-top:8px;font-size:10px;">↺ Retry</button></div>`;
  }
}

function _aliensRenderNoGame() {
  // Calculate days until next Friday 6 PM IST
  const now = new Date();
  // IST = UTC+5:30. Get current time in IST
  const istNow = new Date(now.getTime() + (5.5 * 3600000) - (now.getTimezoneOffset() * 60000));
  const dayOfWeek = istNow.getDay(); // 0 = Sunday, 5 = Friday
  let daysUntilFri = (5 - dayOfWeek + 7) % 7;
  if (daysUntilFri === 0 && istNow.getHours() >= 18) daysUntilFri = 7;
  const label = daysUntilFri === 0 ? 'Today!' : daysUntilFri === 1 ? 'Tomorrow' : `In ${daysUntilFri} days`;
  return `
    <div class="glass-card" style="padding:20px;text-align:center;border:1px solid #bf5af255;background:rgba(191,90,242,0.04);">
      <div style="font-size:36px;margin-bottom:8px;">🛸</div>
      <div style="font-size:11px;font-weight:900;color:#bf5af2;letter-spacing:2px;text-transform:uppercase;">Next Game: ${label}</div>
      <div style="font-size:10px;color:var(--text-muted);margin-top:8px;line-height:1.6;">
        Friday 6 PM IST · Mafia game across all teams<br>
        Lobby opens 30 min before — check back to claim your spot 💜
      </div>
      <div style="font-size:9px;color:var(--text-ghost);margin-top:10px;">HQ will push a notification when the lobby opens</div>
    </div>`;
}
window.renderAliens = renderAliens;

