window.showAliensHowToPlay = showAliensHowToPlay;

function _aliensRenderByPhase(d) {
  switch (d.phase) {
    case 'waiting':       return _aliensRenderWaiting(d);
    case 'lobby_open':    return _aliensRenderLobby(d);
    case 'preparing':     return _aliensRenderPreparing(d);
    case 'round_reveal':
    case 'round_active':
    case 'round_results': return _aliensRenderRound(d);
    case 'completed':     return _aliensRenderCompleted(d);
    case 'cancelled':     return _aliensRenderCancelled(d);
    default:              return `<div style="text-align:center;padding:20px;font-size:11px;color:var(--text-muted);">Phase: ${sanitize(d.phase)}</div>`;
  }
}

function _aliensRenderWaiting(d) {
  const lobbyTime = new Date(d.lobbyOpensAt);
  return `
    <div class="glass-card" style="padding:18px;text-align:center;border:1px solid #bf5af255;background:rgba(191,90,242,0.04);">
      <div style="font-size:28px;margin-bottom:8px;">🛸</div>
      <div style="font-size:12px;font-weight:800;color:#bf5af2;">Aliens scheduled</div>
      <div style="font-size:10px;color:var(--text-muted);margin-top:6px;">Lobby opens at ${lobbyTime.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata', hour: 'numeric', minute: '2-digit', weekday: 'short' })} IST</div>
      <div style="font-size:9px;color:var(--text-ghost);margin-top:4px;">${Math.floor(d.secondsLeft / 60)} min until lobby opens</div>
    </div>`;
}

function _aliensRenderLobby(d) {
  const mins = Math.floor(d.secondsLeft / 60);
  const secs = d.secondsLeft % 60;
  return `
    <div class="glass-card" style="padding:18px;border:1px solid #bf5af255;background:rgba(191,90,242,0.06);">
      <div style="text-align:center;margin-bottom:14px;">
        <div style="font-size:30px;">🛸</div>
        <div style="font-size:12px;font-weight:900;color:#bf5af2;letter-spacing:2px;text-transform:uppercase;">Lobby Open</div>
        <div style="font-size:10px;color:var(--text-muted);margin-top:4px;">Game starts in <strong style="color:#fff;">${mins}m ${secs}s</strong></div>
      </div>
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;padding:10px 14px;background:rgba(255,255,255,0.04);border-radius:8px;">
        <div>
          <div style="font-size:18px;font-weight:900;color:#fff;font-family:var(--font-mono);">${d.lobbyCount} <span style="font-size:11px;color:var(--text-muted);">/ ${d.minPlayers}+</span></div>
          <div style="font-size:9px;color:var(--text-ghost);">Players available</div>
        </div>
        <div style="font-size:9px;color:${d.lobbyCount >= d.minPlayers ? 'var(--green)' : 'var(--courage-amber)'};text-align:right;">
          ${d.lobbyCount >= d.minPlayers ? '✅ Enough players — game will start!' : `Need ${d.minPlayers - d.lobbyCount} more to start`}
        </div>
      </div>
      ${d.inLobby
        ? `<div style="text-align:center;color:var(--green);font-size:11px;font-weight:700;margin-bottom:10px;">✅ You're in the lobby</div>
           <button onclick="aliensLeaveLobby()" class="btn-outline" style="width:100%;border-color:var(--text-muted);color:var(--text-muted);font-size:10px;">Change my mind</button>`
        : `<button onclick="aliensJoinLobby()" class="btn-red" style="width:100%;padding:12px;font-size:11px;">🛸 I'm Available</button>`}
    </div>`;
}

function _aliensRenderPreparing(d) {
  const role = d.myRole;
  if (!role) {
    return `<div class="glass-card" style="padding:18px;text-align:center;border:1px solid #bf5af255;">
      <div style="font-size:30px;">🛸</div>
      <div style="font-size:11px;color:var(--text-muted);margin-top:8px;">You weren't selected this game — watch the GC for updates!</div>
    </div>`;
  }
  if (role === 'mafia') {
    return _aliensRenderMafiaDossier(d);
  }
  const roleColors = { helper: '#ffd60a', sheriff: '#5ac8fa', town: '#fff' };
  const roleIcons = { helper: '🛡️', sheriff: '🔫', town: '👥' };
  const roleLines = {
    helper: 'You will receive intel after each code break. Help town find the mafia.',
    sheriff: 'You get 1 bullet — unlocks after 3 code breaks. Pick wisely.',
    town: 'Authenticate when it\'s your turn in the code sequence. Don\'t press otherwise!',
  };
  return `
    <div class="glass-card" style="padding:20px;text-align:center;border:1px solid ${roleColors[role]}55;background:rgba(191,90,242,0.04);">
      <div style="font-size:36px;margin-bottom:8px;">${roleIcons[role]}</div>
      <div style="font-size:9px;font-weight:900;color:${roleColors[role]};letter-spacing:3px;text-transform:uppercase;">Your Role</div>
      <div style="font-size:18px;font-weight:900;color:#fff;margin:6px 0 10px;text-transform:uppercase;">${role}</div>
      <div style="font-size:10px;color:var(--text-muted);line-height:1.6;margin-bottom:10px;">${roleLines[role]}</div>
      <div style="font-size:9px;color:var(--text-ghost);">Round 1 starts in ${d.secondsLeft}s</div>
    </div>`;
}

function _aliensRenderMafiaDossier(d) {
  const partners = (d.myMafiaPartners || []).map(p => sanitize(p)).join(', ') || '(solo)';
  if (d.myDossier) {
    return `
      <div class="glass-card" style="padding:18px;border:1px solid #ff453a55;background:rgba(255,69,58,0.06);">
        <div style="text-align:center;margin-bottom:12px;">
          <div style="font-size:30px;">🛸</div>
          <div style="font-size:10px;font-weight:900;color:#ff453a;letter-spacing:2px;">You are MAFIA</div>
          <div style="font-size:9px;color:var(--text-muted);margin-top:4px;">Partners: ${partners}</div>
        </div>
        <div style="background:rgba(0,0,0,0.3);padding:10px 12px;border-radius:6px;font-size:10px;color:var(--text-muted);line-height:1.6;">
          ✅ Alibi locked in. Your answers will leak as hints after each code break — keep your story straight. Round 1 in ${d.secondsLeft}s.
        </div>
      </div>`;
  }
  const opts = (arr, name) => arr.map(o => `<option value="${sanitize(o)}">${sanitize(o)}</option>`).join('');
  return `
    <div class="glass-card" style="padding:18px;border:1px solid #ff453a55;background:rgba(255,69,58,0.06);">
      <div style="text-align:center;margin-bottom:14px;">
        <div style="font-size:30px;">🛸</div>
        <div style="font-size:10px;font-weight:900;color:#ff453a;letter-spacing:2px;">You are MAFIA</div>
        <div style="font-size:9px;color:var(--text-muted);margin-top:4px;">Partners: ${partners}</div>
      </div>
      <div style="font-size:10px;color:var(--text-muted);line-height:1.6;margin-bottom:14px;padding:10px 12px;background:rgba(0,0,0,0.3);border-radius:6px;">
        ⚠️ <strong style="color:#ff9f0a;">Set your alibi.</strong> These 3 answers go into a pool — after each code break, helpers see 1 random hint. Lie carefully or tell the truth. No answer = "refused alibi" hint.
      </div>
      <div style="margin-bottom:10px;">
        <label style="font-size:9px;color:var(--text-muted);text-transform:uppercase;letter-spacing:1px;">${sanitize(d.questions.q1_member.label)}</label>
        <select id="alienQ1" style="width:100%;background:rgba(255,255,255,0.06);border:1px solid var(--border-subtle);border-radius:6px;padding:8px 10px;color:#fff;font-size:11px;margin-top:4px;">
          <option value="">— Pick one —</option>${opts(d.questions.q1_member.options)}
        </select>
      </div>
      <div style="margin-bottom:10px;">
        <label style="font-size:9px;color:var(--text-muted);text-transform:uppercase;letter-spacing:1px;">${sanitize(d.questions.q2_stream_time.label)}</label>
        <select id="alienQ2" style="width:100%;background:rgba(255,255,255,0.06);border:1px solid var(--border-subtle);border-radius:6px;padding:8px 10px;color:#fff;font-size:11px;margin-top:4px;">
          <option value="">— Pick one —</option>${opts(d.questions.q2_stream_time.options)}
        </select>
      </div>
      <div style="margin-bottom:14px;">
        <label style="font-size:9px;color:var(--text-muted);text-transform:uppercase;letter-spacing:1px;">${sanitize(d.questions.q3_track.label)}</label>
        <select id="alienQ3" style="width:100%;background:rgba(255,255,255,0.06);border:1px solid var(--border-subtle);border-radius:6px;padding:8px 10px;color:#fff;font-size:11px;margin-top:4px;">
          <option value="">— Pick one —</option>${opts(d.questions.q3_track.options)}
        </select>
      </div>
      <button onclick="aliensSubmitDossier()" class="btn-red" style="width:100%;padding:12px;font-size:11px;">🛸 Lock In Alibi</button>
    </div>`;
}

function _aliensRenderRound(d) {
  const r = d.currentRound;
  const role = d.myRole || 'spectator';
  const roleColors = { mafia: '#ff453a', helper: '#ffd60a', sheriff: '#5ac8fa', town: '#fff' };
  const roleIcons = { mafia: '🛸', helper: '🛡️', sheriff: '🔫', town: '👥' };
  // Sequence display
  let seqHtml = '<div style="display:flex;flex-wrap:wrap;gap:6px;justify-content:center;margin:10px 0;">';
  r.sequence.forEach((agent, i) => {
    const isMe = agent === STATE.agentNo;
    const isPast = r.slotIndex > i;
    const isCurrent = r.slotIndex === i && d.phase === 'round_active';
    const color = isPast ? 'var(--green)' : isCurrent ? 'var(--courage-amber)' : 'var(--text-muted)';
    const bg = isCurrent ? 'rgba(255,159,10,0.15)' : 'rgba(255,255,255,0.04)';
    seqHtml += `<div style="display:flex;align-items:center;gap:4px;background:${bg};border:1px solid ${color}55;border-radius:6px;padding:6px 10px;font-family:var(--font-mono);font-size:11px;font-weight:${isMe?'900':'600'};color:${color};">
      ${isMe ? '👉 ' : ''}${sanitize(agent)}${isPast ? ' ✅' : isCurrent ? ' ⏳' : ''}
    </div>`;
    if (i < r.sequence.length - 1) seqHtml += `<span style="color:var(--text-ghost);align-self:center;">→</span>`;
  });
  seqHtml += '</div>';
  // Action area
  let actionHtml = '';
  if (d.phase === 'round_reveal') {
    actionHtml = `<div style="text-align:center;font-size:10px;color:var(--text-muted);margin:14px 0;">Standby — slot 1 opens in ${d.secondsLeft}s</div>`;
  } else if (d.phase === 'round_active') {
    if (r.isInSequence) {
      actionHtml = r.isMyTurn
        ? `<button onclick="aliensAuthenticate()" class="btn-red" style="width:100%;padding:14px;font-size:12px;">🔓 AUTHENTICATE — ${d.secondsLeft}s left</button>`
        : `<div style="text-align:center;font-size:11px;color:var(--text-muted);margin:10px 0;">⏳ Wait for your slot (you're position ${r.myPosition + 1})</div>`;
    } else {
      actionHtml = role === 'mafia'
        ? `<button onclick="aliensAuthenticate()" class="btn-outline" style="width:100%;padding:10px;border-color:#ff453a;color:#ff453a;font-size:10px;">🛸 Press to disrupt (you're not in sequence)</button>`
        : `<div style="text-align:center;font-size:10px;color:var(--text-muted);margin:10px 0;">You're not in this round's code. Don't press anything!</div>`;
    }
  } else if (d.phase === 'round_results') {
    const passed = r.result === 'passed';
    actionHtml = `<div style="text-align:center;padding:12px;background:${passed?'rgba(52,199,89,0.1)':'rgba(255,69,58,0.1)'};border-radius:6px;border:1px solid ${passed?'#34c75955':'#ff453a55'};margin:10px 0;">
      <div style="font-size:14px;font-weight:900;color:${passed?'var(--green)':'var(--fail)'};">${passed ? '✅ CODE PASSED' : '❌ CODE BROKEN'}</div>
      ${!passed && r.brokenReason ? `<div style="font-size:9px;color:var(--text-muted);margin-top:4px;">Reason: ${sanitize(r.brokenReason).replace(/_/g,' ')}</div>` : ''}
    </div>`;
  }
  // Hints (helpers + sheriff)
  let hintsHtml = '';
  if ((role === 'helper' || role === 'sheriff') && (d.hints || []).length > 0) {
    hintsHtml = `<div style="margin-top:14px;padding:10px 12px;background:rgba(255,214,10,0.06);border:1px solid rgba(255,214,10,0.4);border-radius:6px;">
      <div style="font-size:9px;font-weight:800;color:#ffd60a;letter-spacing:1px;margin-bottom:6px;">📡 INTERCEPTED ALIBIS</div>
      ${d.hints.map(h => `<div style="font-size:10px;color:var(--text-muted);line-height:1.6;margin-bottom:4px;">${h.hintText.replace(/\*\*(.+?)\*\*/g, '<strong style="color:#fff;">$1</strong>')}</div>`).join('')}
    </div>`;
  }
  // Sheriff bullet UI
  let sheriffHtml = '';
  if (role === 'sheriff' && d.sheriffBulletAvailable && !d.sheriffHasShot) {
    sheriffHtml = `<div style="margin-top:14px;padding:14px;background:rgba(90,200,250,0.08);border:1px solid #5ac8fa55;border-radius:6px;">
      <div style="font-size:10px;font-weight:900;color:#5ac8fa;letter-spacing:1px;margin-bottom:8px;text-align:center;">🔫 BULLET UNLOCKED</div>
      <div style="font-size:9px;color:var(--text-muted);margin-bottom:8px;text-align:center;">Type the Agent No. you suspect is mafia:</div>
      <div style="display:flex;gap:6px;">
        <input id="sheriffTarget" placeholder="AGENT001" style="flex:1;background:rgba(255,255,255,0.06);border:1px solid var(--border-subtle);border-radius:6px;padding:8px 10px;color:#fff;font-family:var(--font-mono);font-size:11px;">
        <button onclick="aliensShoot()" class="btn-red" style="padding:8px 14px;font-size:10px;">🔫 SHOOT</button>
      </div>
    </div>`;
  } else if (role === 'sheriff' && !d.sheriffBulletAvailable && !d.sheriffHasShot) {
    sheriffHtml = `<div style="margin-top:10px;text-align:center;font-size:9px;color:var(--text-ghost);">🔒 Bullet unlocks after 3 code breaks (${d.codeBreaksTotal}/3)</div>`;
  }
  return `
    <div class="glass-card" style="padding:18px;border:1px solid ${roleColors[role] || '#bf5af2'}55;background:rgba(191,90,242,0.04);">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">
        <div style="font-size:9px;font-weight:900;color:#bf5af2;letter-spacing:2px;">ROUND ${r.roundNumber} / 3</div>
        <div style="font-size:9px;color:var(--text-muted);">${roleIcons[role] || '👤'} You: <strong style="color:${roleColors[role]||'#fff'};">${role.toUpperCase()}</strong></div>
      </div>
      <div style="font-size:9px;color:var(--text-muted);text-align:center;margin-bottom:4px;text-transform:uppercase;letter-spacing:1px;">Code Sequence</div>
      ${seqHtml}
      ${actionHtml}
      ${hintsHtml}
      ${sheriffHtml}
      <div style="display:flex;justify-content:space-between;margin-top:14px;padding-top:10px;border-top:1px solid var(--border-subtle);font-size:9px;color:var(--text-ghost);">
        <span>Code breaks: <strong style="color:var(--fail);">${d.codeBreaksTotal || 0}</strong></span>
        <span>${d.phase === 'round_active' ? `Slot ${(r.slotIndex || 0) + 1}/${r.sequence.length}` : d.phase}</span>
      </div>
    </div>`;
}

function _aliensRenderCompleted(d) {
  const won = d.winner === 'town' ? (d.myRole !== 'mafia') : (d.myRole === 'mafia');
  return `
    <div class="glass-card" style="padding:20px;text-align:center;border:1px solid ${won ? 'var(--green)' : 'var(--fail)'}55;background:${won ? 'rgba(52,199,89,0.06)' : 'rgba(255,69,58,0.06)'};">
      <div style="font-size:36px;margin-bottom:8px;">${d.winner === 'town' ? '🛡️' : '🛸'}</div>
      <div style="font-size:14px;font-weight:900;color:${won?'var(--green)':'var(--fail)'};">${won ? 'YOU WON!' : 'YOU LOST'}</div>
      <div style="font-size:11px;color:#fff;margin-top:4px;">${d.winner === 'town' ? 'TOWN' : 'MAFIA'} take the night</div>
      <div style="font-size:9px;color:var(--text-muted);margin-top:6px;">+${won ? 30 : 5} XP earned · See you next Friday 💜</div>
    </div>`;
}

function _aliensRenderCancelled(d) {
  return `
    <div class="glass-card" style="padding:18px;text-align:center;border:1px solid var(--text-muted)55;">
      <div style="font-size:28px;">🛸</div>
      <div style="font-size:11px;color:var(--text-muted);margin-top:6px;">Game cancelled${d.reason === 'not_enough_players' ? ` — only ${d.count}/${d.minRequired} players joined.` : '.'}</div>
      <div style="font-size:9px;color:var(--text-ghost);margin-top:4px;">See you next Friday!</div>
    </div>`;
}

async function aliensJoinLobby() {
  const res = await Api.call('aliensJoinLobby', { agentNo: STATE.agentNo }, { cache: false });
  if (res.success) { showToast(res.message, 'success'); renderAliens(); }
  else showToast(res.error, 'error');
}
window.aliensJoinLobby = aliensJoinLobby;

async function aliensLeaveLobby() {
  const res = await Api.call('aliensLeaveLobby', { agentNo: STATE.agentNo }, { cache: false });
  if (res.success) { showToast(res.message, 'success'); renderAliens(); }
  else showToast(res.error, 'error');
}
window.aliensLeaveLobby = aliensLeaveLobby;

async function aliensSubmitDossier() {
  const q1 = document.getElementById('alienQ1')?.value;
  const q2 = document.getElementById('alienQ2')?.value;
  const q3 = document.getElementById('alienQ3')?.value;
  if (!q1 || !q2 || !q3) { showToast('Answer all 3 questions', 'error'); return; }
  const res = await Api.call('aliensSubmitDossier', { agentNo: STATE.agentNo, q1, q2, q3 }, { cache: false });
  if (res.success) { showToast(res.message, 'success'); renderAliens(); }
  else showToast(res.error, 'error');
}
window.aliensSubmitDossier = aliensSubmitDossier;

async function aliensAuthenticate() {
  const res = await Api.call('aliensAuthenticate', { agentNo: STATE.agentNo }, { cache: false });
  if (res.success) { showToast(res.message, res.wasCorrect ? 'success' : 'error'); renderAliens(); }
  else showToast(res.error, 'error');
}
window.aliensAuthenticate = aliensAuthenticate;

async function aliensShoot() {
  const target = document.getElementById('sheriffTarget')?.value?.trim().toUpperCase();
  if (!target) { showToast('Type a target Agent No.', 'error'); return; }
  if (!confirm(`Shoot ${target}? You only get 1 bullet!`)) return;
  const res = await Api.call('aliensShoot', { agentNo: STATE.agentNo, targetAgentNo: target }, { cache: false });
  if (res.success) { showToast(res.message, res.wasCorrect ? 'success' : 'error'); renderAliens(); }
  else showToast(res.error, 'error');
}
window.aliensShoot = aliensShoot;
window.renderGames = renderGames;

// ══════════════════════════════════════════════════════════════════════
// GAME 5 — CIPHER PROTOCOL
// ══════════════════════════════════════════════════════════════════════

async function renderCipherProtocol() {
  const container = $('cipherContent');
  if (!container) return;
  container.innerHTML = `
    <div class="glass-card" style="padding:24px;text-align:center;border:1px solid var(--border-subtle);background:rgba(255,255,255,0.02);">
      <div style="font-size:36px;margin-bottom:10px;">🔐</div>
      <div style="font-size:12px;font-weight:900;color:var(--text-primary);margin-bottom:6px;">Not Live Yet</div>
      <div style="font-size:10px;color:var(--text-muted);line-height:1.7;">Cipher Protocol is offline right now.<br>Daily ciphers will drop when HQ activates this module 🔒</div>
    </div>`;
  return;
  try {
    const d = await Api.call('getCipherStatus', { agentNo: STATE.agentNo }, { cache: false });
    if (!d.success) { container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">${sanitize(d.error)}</div>`; return; }
    if (d.hasSubmitted) {
      const color = d.isCorrect ? 'var(--green)' : 'var(--fail)';
      container.innerHTML = `
        <div class="glass-card" style="padding:18px;text-align:center;border:1px solid ${color}55;background:${color}08;">
          <div style="font-size:28px;margin-bottom:8px;">${d.isCorrect ? '✅' : '❌'}</div>
          <div style="font-size:12px;font-weight:800;color:${color};margin-bottom:6px;">${d.isCorrect ? 'Cracked it!' : 'Not quite!'}</div>
          <div style="font-size:10px;color:var(--text-muted);margin-bottom:8px;">The song was: <strong style="color:#fff;">${sanitize(d.correctAnswer)}</strong></div>
          ${d.isCorrect ? `<div style="font-size:10px;color:var(--green);font-weight:700;">+8 XP earned 🔐</div>` : `<div style="font-size:10px;color:var(--text-muted);">You answered: "${sanitize(d.submittedAnswer)}" · Come back tomorrow!</div>`}
        </div>`;
      return;
    }
    container.innerHTML = `
      <div class="glass-card" style="padding:20px;text-align:center;border:1px solid #34c75955;background:rgba(52,199,89,0.04);">
        <div style="font-size:9px;font-weight:900;color:#34c759;letter-spacing:3px;text-transform:uppercase;margin-bottom:12px;">🔐 Today's Cipher</div>
        <div style="font-size:36px;font-weight:900;color:#fff;letter-spacing:10px;font-family:var(--font-mono);margin-bottom:8px;">${sanitize(d.initials)}</div>
        <div style="font-size:9px;color:var(--text-ghost);margin-bottom:18px;">These are the initials of a BTS song — name it!</div>
        <div style="display:flex;gap:8px;max-width:340px;margin:0 auto;">
          <input id="cipherInput" type="text" maxlength="80" placeholder="Type the full song title…"
            style="flex:1;background:rgba(255,255,255,0.06);border:1px solid var(--border-subtle);border-radius:6px;padding:10px 12px;color:#fff;font-size:12px;"
            onkeydown="if(event.key==='Enter')submitCipherAnswer()">
          <button onclick="submitCipherAnswer()" class="btn-outline" style="border-color:#34c759;color:#34c759;padding:10px 14px;white-space:nowrap;">Submit</button>
        </div>
        <div style="font-size:9px;color:var(--text-ghost);margin-top:10px;">One attempt per day · +8 XP for correct answer</div>
      </div>`;
  } catch (e) {
    container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">Failed to load.<br><button onclick="renderCipherProtocol()" class="btn-outline" style="margin-top:8px;font-size:10px;">↺ Retry</button></div>`;
  }
}
window.renderCipherProtocol = renderCipherProtocol;

async function submitCipherAnswer() {
  const input = document.getElementById('cipherInput');
  const answer = input?.value?.trim();
  if (!answer) { showToast('Type an answer first', 'error'); return; }
  const btn = input?.nextElementSibling;
  if (btn) btn.disabled = true;
  const res = await Api.call('submitCipherAnswer', { agentNo: STATE.agentNo, answer }, { cache: false });
  if (res.success) { showToast(res.message, res.isCorrect ? 'success' : 'error'); renderCipherProtocol(); }
  else { showToast(res.error, 'error'); if (btn) btn.disabled = false; }
}
window.submitCipherAnswer = submitCipherAnswer;

// ══════════════════════════════════════════════════════════════════════
// GAME 6 — BALANCE GAME
// ══════════════════════════════════════════════════════════════════════

async function renderBalanceGame() {
  const container = $('balanceContent');
  if (!container) return;
  container.innerHTML = `
    <div class="glass-card" style="padding:24px;text-align:center;border:1px solid var(--border-subtle);background:rgba(255,255,255,0.02);">
      <div style="font-size:36px;margin-bottom:10px;">⚖️</div>
      <div style="font-size:12px;font-weight:900;color:var(--text-primary);margin-bottom:6px;">Not Live Yet</div>
      <div style="font-size:10px;color:var(--text-muted);line-height:1.7;">Balance Game is offline right now.<br>Daily dilemmas will return when HQ flips the switch 💬</div>
    </div>`;
  return;
  try {
    const d = await Api.call('getBalanceStatus', { agentNo: STATE.agentNo }, { cache: false });
    if (!d.success) { container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">${sanitize(d.error)}</div>`; return; }
    const team = STATE.data?.agent?.profile?.team;
    if (d.hasVoted && d.results) {
      const r = d.results;
      const myA = d.myChoice === 'A';
      const aColor = myA ? '#ff9f0a' : 'var(--text-muted)';
      const bColor = !myA ? '#ff9f0a' : 'var(--text-muted)';
      container.innerHTML = `
        <div class="glass-card" style="padding:18px;border:1px solid #ff9f0a55;background:rgba(255,159,10,0.05);">
          <div style="font-size:9px;font-weight:900;color:#ff9f0a;letter-spacing:2px;text-transform:uppercase;text-align:center;margin-bottom:14px;">📊 ${r.total} votes in — your pick: <span style="color:#fff;">Option ${d.myChoice}</span></div>
          <div style="display:flex;flex-direction:column;gap:10px;">
            <div style="border-left:3px solid ${aColor};padding:10px 12px;background:${myA?'rgba(255,159,10,0.08)':'rgba(255,255,255,0.02)'};border-radius:0 6px 6px 0;">
              <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
                <div style="font-size:10px;font-weight:800;color:${aColor};">A ${myA?'← your pick':''}</div>
                <div style="font-size:14px;font-weight:900;color:${aColor};">${r.aPct}%</div>
              </div>
              <div style="font-size:10px;color:var(--text-muted);line-height:1.5;">${sanitize(d.optionA)}</div>
              <div style="background:rgba(255,255,255,0.06);border-radius:4px;height:4px;margin-top:8px;overflow:hidden;">
                <div style="width:${r.aPct}%;height:100%;background:#ff9f0a;border-radius:4px;"></div>
              </div>
            </div>
            <div style="border-left:3px solid ${bColor};padding:10px 12px;background:${!myA?'rgba(255,159,10,0.08)':'rgba(255,255,255,0.02)'};border-radius:0 6px 6px 0;">
              <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
                <div style="font-size:10px;font-weight:800;color:${bColor};">B ${!myA?'← your pick':''}</div>
                <div style="font-size:14px;font-weight:900;color:${bColor};">${r.bPct}%</div>
              </div>
              <div style="font-size:10px;color:var(--text-muted);line-height:1.5;">${sanitize(d.optionB)}</div>
              <div style="background:rgba(255,255,255,0.06);border-radius:4px;height:4px;margin-top:8px;overflow:hidden;">
                <div style="width:${r.bPct}%;height:100%;background:#ff9f0a;border-radius:4px;"></div>
              </div>
            </div>
          </div>
          <div style="font-size:9px;color:var(--text-ghost);text-align:center;margin-top:10px;">New dilemma drops at midnight KST 💬</div>
        </div>`;
      return;
    }
    container.innerHTML = `
      <div class="glass-card" style="padding:18px;border:1px solid #ff9f0a55;background:rgba(255,159,10,0.04);">
        <div style="font-size:9px;font-weight:900;color:#ff9f0a;letter-spacing:2px;text-transform:uppercase;text-align:center;margin-bottom:14px;">⚖️ Today's Dilemma — Pick One</div>
        <div style="display:flex;flex-direction:column;gap:10px;">
          <button onclick="castBalanceVote('A')" style="text-align:left;background:rgba(255,159,10,0.06);border:1px solid #ff9f0a55;border-radius:8px;padding:14px 16px;color:#fff;cursor:pointer;transition:all 0.2s;" onmouseover="this.style.background='rgba(255,159,10,0.15)'" onmouseout="this.style.background='rgba(255,159,10,0.06)'">
            <div style="font-size:9px;font-weight:900;color:#ff9f0a;letter-spacing:2px;margin-bottom:6px;">OPTION A</div>
            <div style="font-size:11px;line-height:1.6;">${sanitize(d.optionA)}</div>
          </button>
          <div style="text-align:center;font-size:9px;color:var(--text-ghost);font-weight:800;letter-spacing:2px;">— OR —</div>
          <button onclick="castBalanceVote('B')" style="text-align:left;background:rgba(255,159,10,0.06);border:1px solid #ff9f0a55;border-radius:8px;padding:14px 16px;color:#fff;cursor:pointer;transition:all 0.2s;" onmouseover="this.style.background='rgba(255,159,10,0.15)'" onmouseout="this.style.background='rgba(255,159,10,0.06)'">
            <div style="font-size:9px;font-weight:900;color:#ff9f0a;letter-spacing:2px;margin-bottom:6px;">OPTION B</div>
            <div style="font-size:11px;line-height:1.6;">${sanitize(d.optionB)}</div>
          </button>
        </div>
        <div style="font-size:9px;color:var(--text-ghost);text-align:center;margin-top:10px;">Tap a side to vote — results revealed instantly 👀</div>
      </div>`;
  } catch (e) {
    container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">Failed to load.<br><button onclick="renderBalanceGame()" class="btn-outline" style="margin-top:8px;font-size:10px;">↺ Retry</button></div>`;
  }
}
window.renderBalanceGame = renderBalanceGame;

async function castBalanceVote(choice) {
  const team = STATE.data?.agent?.profile?.team || '';
  const res = await Api.call('submitBalanceVote', { agentNo: STATE.agentNo, team, choice }, { cache: false });
  if (res.success) { showToast(res.message, 'success'); renderBalanceGame(); }
  else showToast(res.error, 'error');
}
window.castBalanceVote = castBalanceVote;

