async function renderSignalChain() {
  const container = $('signalContent');
  if (!container) return;
  container.innerHTML = `
    <div class="glass-card" style="padding:24px;text-align:center;border:1px solid var(--border-subtle);background:rgba(255,255,255,0.02);">
      <div style="font-size:36px;margin-bottom:10px;">🔗</div>
      <div style="font-size:12px;font-weight:900;color:var(--text-primary);margin-bottom:6px;">Not Live Yet</div>
      <div style="font-size:10px;color:var(--text-muted);line-height:1.7;">Eat This Life is offline right now.<br>Word relay chains will begin when HQ opens this module 🔗</div>
    </div>`;
  return;
  try {
    const team = STATE.data?.agent?.profile?.team;
    if (!team) { container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">Log in to access Signal Chain.</div>`; return; }
    const d = await Api.call('getSignalChain', { agentNo: STATE.agentNo, team }, { cache: false });
    if (!d.success) { container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">${sanitize(d.error)}</div>`; return; }
    const words = d.words || [];
    let chainHtml = '';
    if (words.length === 0) {
      chainHtml = `<div style="font-size:10px;color:var(--text-ghost);text-align:center;padding:12px;">No words yet — be the first to start the chain!</div>`;
    } else {
      chainHtml = `<div style="display:flex;flex-wrap:wrap;gap:6px;padding:10px 0;">`;
      words.forEach((w, i) => {
        const isMe = w.agentNo === STATE.agentNo;
        chainHtml += `<div style="display:flex;align-items:center;gap:4px;">
          <span style="font-size:12px;font-weight:${isMe?'900':'700'};color:${isMe?'#5ac8fa':'#fff'};background:rgba(255,255,255,0.06);border:1px solid ${isMe?'#5ac8fa55':'var(--border-subtle)'};border-radius:4px;padding:4px 8px;font-family:var(--font-mono);">${sanitize(w.word)}</span>
          ${i < words.length - 1 ? '<span style="color:var(--text-ghost);font-size:10px;">→</span>' : ''}
        </div>`;
      });
      chainHtml += `</div>`;
    }
    let actionHtml = '';
    if (d.hasAdded) {
      actionHtml = `<div class="glass-card" style="padding:12px;text-align:center;border:1px solid #5ac8fa55;background:rgba(90,200,250,0.05);">
        <div style="font-size:11px;font-weight:800;color:#5ac8fa;">✅ You added: <span style="font-family:var(--font-mono);">${sanitize(d.myWord)}</span></div>
        <div style="font-size:9px;color:var(--text-ghost);margin-top:4px;">+5 XP earned · Come back tomorrow to add another word!</div>
      </div>`;
    } else {
      const hint = d.nextLetter
        ? `Must start with <strong style="color:#5ac8fa;font-size:12px;font-family:var(--font-mono);">${d.nextLetter}</strong>`
        : `Start the chain with any word!`;
      actionHtml = `<div class="glass-card" style="padding:14px;">
        <div style="font-size:9px;color:var(--text-muted);margin-bottom:8px;">Your word — ${hint}</div>
        <div style="display:flex;gap:8px;">
          <input id="signalInput" type="text" maxlength="30" placeholder="Type your word…"
            style="flex:1;background:rgba(255,255,255,0.06);border:1px solid var(--border-subtle);border-radius:6px;padding:10px 12px;color:#fff;font-size:13px;font-family:var(--font-mono);"
            onkeydown="if(event.key==='Enter')addSignalWord()">
          <button onclick="addSignalWord()" class="btn-outline" style="border-color:#5ac8fa;color:#5ac8fa;padding:10px 14px;white-space:nowrap;">Add +2 XP</button>
        </div>
      </div>`;
    }
    container.innerHTML = `
      <div class="glass-card" style="padding:16px;border:1px solid #5ac8fa55;background:rgba(90,200,250,0.04);margin-bottom:10px;">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
          <div style="font-size:9px;font-weight:900;color:#5ac8fa;letter-spacing:2px;text-transform:uppercase;">🔗 Today's Chain — ${words.length} word${words.length!==1?'s':''}</div>
        </div>
        ${chainHtml}
      </div>
      ${actionHtml}`;
  } catch (e) {
    container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">Failed to load.<br><button onclick="renderSignalChain()" class="btn-outline" style="margin-top:8px;font-size:10px;">↺ Retry</button></div>`;
  }
}
window.renderSignalChain = renderSignalChain;

async function addSignalWord() {
  const input = document.getElementById('signalInput');
  const word = input?.value?.trim();
  if (!word) { showToast('Type a word first', 'error'); return; }
  const team = STATE.data?.agent?.profile?.team || '';
  const btn = input?.nextElementSibling;
  if (btn) btn.disabled = true;
  const res = await Api.call('submitSignalWord', { agentNo: STATE.agentNo, team, word }, { cache: false });
  if (res.success) { showToast(res.message, 'success'); renderSignalChain(); }
  else { showToast(res.error, 'error'); if (btn) btn.disabled = false; }
}
window.addSignalWord = addSignalWord;

