let _rfState = null;

async function renderRapidFire() {
  const container = $('rapidFireContent');
  if (!container) return;
  container.innerHTML = `
    <div class="glass-card" style="padding:24px;text-align:center;border:1px solid var(--border-subtle);background:rgba(255,255,255,0.02);">
      <div style="font-size:36px;margin-bottom:10px;">⚡</div>
      <div style="font-size:12px;font-weight:900;color:var(--text-primary);margin-bottom:6px;">Not Live Yet</div>
      <div style="font-size:10px;color:var(--text-muted);line-height:1.7;">That's Fire is offline right now.<br>Rapid-fire trivia rounds will ignite when HQ activates this module ⚡</div>
    </div>`;
  return;
  try {
    const d = await Api.call('getRapidFireQuestions', { agentNo: STATE.agentNo }, { cache: false });
    if (!d.success) { container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">${sanitize(d.error)}</div>`; return; }
    if (d.hasPlayed) {
      const pct = Math.round((d.score / d.total) * 100);
      const color = d.score === d.total ? 'var(--green)' : d.score >= 3 ? 'var(--courage-amber)' : 'var(--fail)';
      container.innerHTML = `
        <div class="glass-card" style="padding:20px;text-align:center;border:1px solid ${color}55;background:${color}08;">
          <div style="font-size:32px;margin-bottom:8px;">${d.score === d.total ? '🔥' : d.score >= 3 ? '⚡' : '📖'}</div>
          <div style="font-size:22px;font-weight:900;color:${color};font-family:var(--font-mono);">${d.score} / ${d.total}</div>
          <div style="font-size:10px;color:var(--text-muted);margin-top:4px;">Today's score · ${d.score * 2} XP earned</div>
          <div style="font-size:9px;color:var(--text-ghost);margin-top:8px;">New questions drop at midnight KST ⚡</div>
        </div>`;
      return;
    }
    // Show start screen
    container.innerHTML = `
      <div class="glass-card" style="padding:24px;text-align:center;border:1px solid var(--fail)55;background:rgba(232,58,93,0.04);">
        <div style="font-size:32px;margin-bottom:12px;">⚡</div>
        <div style="font-size:14px;font-weight:900;color:#fff;margin-bottom:6px;">That's Fire ⚡</div>
        <div style="font-size:10px;color:var(--text-muted);line-height:1.6;margin-bottom:6px;">5 questions · 7 seconds each · answer before it burns out</div>
        <div style="display:flex;justify-content:center;gap:16px;margin:14px 0;">
          <div style="text-align:center;"><div style="font-size:18px;font-weight:900;color:var(--fail);">5</div><div style="font-size:8px;color:var(--text-ghost);">Questions</div></div>
          <div style="text-align:center;"><div style="font-size:18px;font-weight:900;color:var(--courage-amber);">7s</div><div style="font-size:8px;color:var(--text-ghost);">Per Q</div></div>
          <div style="text-align:center;"><div style="font-size:18px;font-weight:900;color:var(--green);">+2</div><div style="font-size:8px;color:var(--text-ghost);">XP each</div></div>
        </div>
        <button onclick="startRapidFire(${JSON.stringify(d.questions).replace(/"/g, '&quot;')})" class="btn-red" style="padding:12px 28px;font-size:11px;margin-top:4px;">⚡ Start Round</button>
      </div>`;
  } catch (e) {
    container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">Failed to load.<br><button onclick="renderRapidFire()" class="btn-outline" style="margin-top:8px;font-size:10px;">↺ Retry</button></div>`;
  }
}
window.renderRapidFire = renderRapidFire;

function startRapidFire(questions) {
  _rfState = { questions, answers: new Array(questions.length).fill(''), currentIdx: 0, timer: null, timeLeft: 7 };
  _rfRenderQuestion();
}
window.startRapidFire = startRapidFire;

function _rfRenderQuestion() {
  const s = _rfState;
  const container = $('rapidFireContent');
  if (!container || !s) return;
  if (s.timer) clearInterval(s.timer);
  s.timeLeft = 7;
  const progress = `${s.currentIdx + 1} / ${s.questions.length}`;
  const pct = ((s.currentIdx) / s.questions.length) * 100;
  container.innerHTML = `
    <div class="glass-card" style="padding:20px;border:1px solid var(--fail)55;background:rgba(232,58,93,0.04);">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">
        <div style="font-size:9px;font-weight:900;color:var(--text-muted);letter-spacing:2px;">Q ${progress}</div>
        <div id="rfTimer" style="font-size:22px;font-weight:900;color:var(--fail);font-family:var(--font-mono);">7</div>
      </div>
      <div style="background:rgba(255,255,255,0.06);border-radius:4px;height:3px;margin-bottom:16px;overflow:hidden;">
        <div style="width:${pct}%;height:100%;background:var(--fail);border-radius:4px;"></div>
      </div>
      <div style="font-size:13px;font-weight:700;color:#fff;line-height:1.5;margin-bottom:16px;min-height:44px;">${sanitize(s.questions[s.currentIdx].q)}</div>
      <input id="rfInput" type="text" maxlength="60" placeholder="Type answer, press Enter…" autofocus
        style="width:100%;box-sizing:border-box;background:rgba(255,255,255,0.06);border:1px solid var(--border-subtle);border-radius:6px;padding:10px 12px;color:#fff;font-size:12px;margin-bottom:10px;"
        onkeydown="if(event.key==='Enter')rfNext()">
      <button onclick="rfNext()" class="btn-red" style="width:100%;padding:10px;font-size:11px;">Next →</button>
    </div>`;
  document.getElementById('rfInput')?.focus();
  s.timer = setInterval(() => {
    s.timeLeft--;
    const el = document.getElementById('rfTimer');
    if (el) {
      el.textContent = s.timeLeft;
      el.style.color = s.timeLeft <= 3 ? 'var(--fail)' : 'var(--courage-amber)';
    }
    if (s.timeLeft <= 0) { clearInterval(s.timer); rfNext(); }
  }, 1000);
}

function rfNext() {
  const s = _rfState;
  if (!s) return;
  if (s.timer) clearInterval(s.timer);
  const input = document.getElementById('rfInput');
  s.answers[s.currentIdx] = input?.value?.trim() || '';
  s.currentIdx++;
  if (s.currentIdx >= s.questions.length) {
    _rfSubmit();
  } else {
    _rfRenderQuestion();
  }
}
window.rfNext = rfNext;

async function _rfSubmit() {
  const container = $('rapidFireContent');
  if (!container) return;
  container.innerHTML = `<div style="padding:30px;text-align:center;color:var(--text-muted);font-size:12px;">⏳ Grading your answers…</div>`;
  const res = await Api.call('submitRapidFireAnswers', { agentNo: STATE.agentNo, answers: _rfState.answers }, { cache: false });
  if (!res.success) { container.innerHTML = `<div style="color:var(--fail);text-align:center;padding:20px;font-size:11px;">${sanitize(res.error)}</div>`; return; }
  const color = res.score === 5 ? 'var(--green)' : res.score >= 3 ? 'var(--courage-amber)' : 'var(--fail)';
  let breakdownHtml = (res.breakdown || []).map(b => `
    <div style="display:flex;align-items:flex-start;gap:10px;padding:8px 0;border-bottom:1px solid var(--border-subtle);">
      <div style="font-size:14px;min-width:20px;">${b.isCorrect ? '✅' : '❌'}</div>
      <div style="flex:1;">
        <div style="font-size:10px;color:#fff;margin-bottom:2px;">${sanitize(b.question)}</div>
        <div style="font-size:9px;color:${b.isCorrect?'var(--green)':'var(--fail)'};">Your answer: <em>${sanitize(b.given)}</em></div>
        ${!b.isCorrect ? `<div style="font-size:9px;color:var(--text-muted);">Correct: <em>${sanitize(b.correct)}</em></div>` : ''}
      </div>
    </div>`).join('');
  container.innerHTML = `
    <div class="glass-card" style="padding:20px;border:1px solid ${color}55;background:${color}08;margin-bottom:12px;text-align:center;">
      <div style="font-size:28px;font-weight:900;color:${color};font-family:var(--font-mono);">${res.score} / ${res.total}</div>
      <div style="font-size:10px;color:var(--text-muted);margin-top:4px;">${sanitize(res.message)}</div>
      ${res.xpEarned > 0 ? `<div style="font-size:11px;color:var(--green);font-weight:800;margin-top:6px;">+${res.xpEarned} XP earned ⚡</div>` : ''}
    </div>
    <div class="glass-card" style="padding:14px;">
      <div style="font-size:9px;font-weight:800;color:var(--text-muted);letter-spacing:1px;text-transform:uppercase;margin-bottom:8px;">Breakdown</div>
      ${breakdownHtml}
    </div>
    <div style="font-size:9px;color:var(--text-ghost);text-align:center;margin-top:10px;">New questions at midnight KST ⚡</div>`;
  _rfState = null;
}
window._rfSubmit = _rfSubmit;

