// ==================== 100XP POPUP (ARIRANG — PSYCHO EDITION) ====================
function check100XPPopup() {
  if (!STATE.data || !STATE.data.agent || !STATE.data.agent.stats) return;
  const currentWeekXP = parseInt(STATE.data.agent.stats.totalXP) || 0;
  const storageKey = `arirang_${STATE.agentNo}_100xp_popup_${STATE.week}`;

  // Only fire when XP just crossed 100 in this session (not on every page load)
  const sessionKey = `_100xp_seen_${STATE.agentNo}_${STATE.week}`;
  const prevXP = parseInt(sessionStorage.getItem(sessionKey) || '0');
  sessionStorage.setItem(sessionKey, String(currentWeekXP));
  const justCrossed = prevXP < 100 && currentWeekXP >= 100;

  if (justCrossed && !localStorage.getItem(storageKey)) {
    const modalId = 'xp-100-modal';
    if (document.getElementById(modalId)) return;

    let badgeUrl = '';
    if (typeof getTacticalBadges === 'function') {
      const badges = getTacticalBadges(STATE.agentNo, currentWeekXP, STATE.week);
      if (badges && badges.length > 0) {
        badgeUrl = badges[0].imageUrl;
      }
    }
    if (!badgeUrl) badgeUrl = CONFIG.TACTICAL_POOL[0];

    const modalHtml = `
            <div id="${modalId}" class="spy-modal-overlay" style="
                z-index: 100000;
                position: fixed;
                inset: 0;
                background: rgba(5, 5, 8, 0.95);
                display: flex;
                align-items: center;
                justify-content: center;
                backdrop-filter: blur(12px);
                animation: fadeIn 0.4s ease;">

                <div style="
                    padding: 0;
                    text-align: center;
                    width: 90%;
                    max-width: 370px;
                    background: linear-gradient(180deg, #0a0a0f 0%, #050508 100%);
                    border: 1px solid rgba(232, 58, 93, 0.3);
                    box-shadow:
                        0 0 40px rgba(232, 58, 93, 0.15),
                        0 0 80px rgba(232, 58, 93, 0.06),
                        inset 0 0 30px rgba(232, 58, 93, 0.03);
                    overflow: hidden;
                    border-radius: 4px;
                    animation: popupSlideUp 0.6s cubic-bezier(0.16, 1, 0.3, 1);">

                    <!-- ── HEADER ── -->
                    <div style="
                        padding: 18px 16px;
                        position: relative;
                        border-bottom: 1px solid rgba(232, 58, 93, 0.12);
                        background: rgba(232, 58, 93, 0.04);">

                        <!-- Top crimson bar -->
                        <div style="
                            position: absolute;
                            top: 0; left: 0; right: 0;
                            height: 2px;
                            background: linear-gradient(90deg,
                                transparent,
                                rgba(232, 58, 93, 0.8),
                                rgba(232, 58, 93, 1),
                                rgba(232, 58, 93, 0.8),
                                transparent);
                            animation: topBarLive 2.5s ease-in-out infinite;">
                        </div>

                        <!-- Header title -->
                        <div style="
                            font-family: 'Orbitron', sans-serif;
                            color: #fff;
                            margin: 0;
                            font-size: 15px;
                            font-weight: 900;
                            letter-spacing: 3px;
                            text-shadow: 0 0 12px rgba(232, 58, 93, 0.5);
                            display: flex;
                            align-items: center;
                            justify-content: center;
                            gap: 10px;">
                            STREAMS GO PSYCHO 🔥
                        </div>
                    </div>

                    <!-- ── BODY ── -->
                    <div style="padding: 26px 24px 28px;">

                        <!-- Fun subtitle -->
                        <div style="
                            font-family: 'Share Tech Mono', monospace;
                            font-size: 10px;
                            color: rgba(232, 58, 93, 0.7);
                            margin-bottom: 22px;
                            text-transform: uppercase;
                            letter-spacing: 3px;
                            animation: blinkSoft 2s ease-in-out infinite;">
                            ◈ ${STATE.agentNo} just went full hooligan ◈
                        </div>

                        <!-- ── BADGE CONTAINER ── -->
                        <div style="
                            position: relative;
                            width: 150px;
                            height: 180px;
                            margin: 0 auto 28px;
                            animation: badgeEntrance 0.8s cubic-bezier(0.34, 1.56, 0.64, 1) 0.3s both;">

                            <!-- Outer dashed ring -->
                            <div style="
                                position: absolute;
                                inset: -16px;
                                border-radius: 4px;
                                border: 1px dashed rgba(232, 58, 93, 0.25);
                                animation: spinSlow 16s linear infinite;">
                            </div>

                            <!-- Inner spinning ring -->
                            <div style="
                                position: absolute;
                                inset: -7px;
                                border-radius: 4px;
                                border: 1.5px solid rgba(232, 58, 93, 0.06);
                                border-top-color: rgba(232, 58, 93, 0.8);
                                border-bottom-color: rgba(232, 58, 93, 0.5);
                                animation: spinFast 6s linear infinite reverse;
                                box-shadow: 0 0 10px rgba(232, 58, 93, 0.2);">
                            </div>

                            <!-- Tactical card -->
                            <div class="tactical-card" style="
                                width: 150px;
                                height: 180px;
                                animation: arirangPulse 3s ease-in-out infinite;">

                                <!-- Corners -->
                                <div class="popup-corner-tl"></div>
                                <div class="popup-corner-br"></div>

                                <!-- Live dot -->
                                <div class="popup-live-dot"></div>

                                <!-- Image wrapper -->
                                <div class="tactical-inner" style="
                                    position: relative;
                                    overflow: hidden;
                                    width: 100%;
                                    height: 100%;">

                                    <img src="${badgeUrl}"
                                         alt="Classified Merit"
                                         style="
                                             width: 100%;
                                             height: 100%;
                                             object-fit: cover;
                                             object-position: top;
                                             animation: softDecrypt 3s ease-out forwards;">

                                    <!-- Scan line -->
                                    <div class="popup-scanline"></div>

                                    <!-- CRT overlay -->
                                    <div class="popup-crt"></div>

                                </div>

                                <div class="tactical-shine"></div>
                            </div>
                        </div>

                        <!-- Fun quote -->
                        <div style="
                            font-family: 'Rajdhani', sans-serif;
                            font-size: 15px;
                            font-weight: 700;
                            color: rgba(255, 255, 255, 0.9);
                            letter-spacing: 1px;
                            margin-bottom: 10px;
                            font-style: italic;">
                            "Watch this stream goin' hooligan!" 🎧
                        </div>

                        <!-- Description -->
                        <p style="
                            font-family: 'Rajdhani', sans-serif;
                            font-size: 13px;
                            margin-bottom: 26px;
                            line-height: 1.8;
                            color: rgba(255, 255, 255, 0.5);">
                            HQ verified you went
                            <span style="color: #e83a5d; font-weight: 700;">full streamer</span>
                            tonight.<br>
                            Your 100 XP made the numbers jump,<br>
                            and this elite merit is
                            <span style="color: #fff; font-weight: 700;">permanently yours.</span>
                        </p>

                        <!-- Button -->
                        <button
                            onclick="
                                localStorage.setItem('${storageKey}', 'true');
                                document.getElementById('${modalId}').remove();
                                if(typeof fireConfetti === 'function') fireConfetti();
                            "
                            style="
                                width: 100%;
                                padding: 15px;
                                font-family: 'Orbitron', sans-serif;
                                font-size: 12px;
                                letter-spacing: 2px;
                                color: #fff;
                                background: linear-gradient(135deg, #e83a5d 0%, #8a0020 100%);
                                border: 1px solid rgba(232, 58, 93, 0.6);
                                border-radius: 6px;
                                cursor: pointer;
                                position: relative;
                                overflow: hidden;
                                box-shadow:
                                    0 0 20px rgba(232, 58, 93, 0.3),
                                    inset 0 1px 4px rgba(255, 255, 255, 0.12);
                                transition: all 0.3s ease;"
                            onmouseover="
                                this.style.transform='translateY(-2px)';
                                this.style.boxShadow='0 0 30px rgba(232,58,93,0.5), inset 0 1px 4px rgba(255,255,255,0.15)';"
                            onmouseout="
                                this.style.transform='translateY(0)';
                                this.style.boxShadow='0 0 20px rgba(232,58,93,0.3), inset 0 1px 4px rgba(255,255,255,0.12)';">

                            WE WANT IT ALL 🏆

                            <!-- Button shimmer -->
                            <div style="
                                position: absolute;
                                top: 0; left: -100%;
                                width: 50%; height: 100%;
                                background: linear-gradient(90deg,
                                    transparent,
                                    rgba(255, 255, 255, 0.2),
                                    transparent);
                                animation: btnShimmer 3.5s ease-in-out infinite;">
                            </div>
                        </button>

                    </div>
                </div>

                <!-- ══════════════════════════════════
                     ALL STYLES — SELF CONTAINED
                     prefix: popup- to avoid conflicts
                     with your global tactical CSS
                ══════════════════════════════════ -->
                <style>

                    /* ── OVERLAY ── */
                    @keyframes fadeIn {
                        from { opacity: 0; }
                        to   { opacity: 1; }
                    }

                    /* ── CARD ENTRANCE ── */
                    @keyframes popupSlideUp {
                        from { transform: translateY(30px) scale(0.95); opacity: 0; }
                        to   { transform: translateY(0)    scale(1);    opacity: 1; }
                    }

                    /* ── BADGE ENTRANCE ── */
                    @keyframes badgeEntrance {
                        from { transform: scale(0.6); opacity: 0; }
                        to   { transform: scale(1);   opacity: 1; }
                    }

                    /* ── IMAGE DECRYPT ── */
                    /* brightness never exceeds 1 — no eye strain */
                    @keyframes softDecrypt {
                        0% {
                            filter: blur(14px) grayscale(100%) brightness(0.2);
                            transform: scale(1.2);
                            opacity: 0;
                        }
                        25% {
                            filter: blur(8px) grayscale(70%) brightness(0.6);
                            opacity: 0.5;
                        }
                        55% {
                            filter: blur(3px) grayscale(20%) brightness(0.9);
                            transform: scale(1.04);
                        }
                        100% {
                            filter: blur(0px) grayscale(0%) brightness(1);
                            transform: scale(1);
                            opacity: 1;
                        }
                    }

                    /* ── RINGS ── */
                    @keyframes spinSlow {
                        100% { transform: rotate(360deg); }
                    }
                    @keyframes spinFast {
                        100% { transform: rotate(360deg); }
                    }

                    /* ── CARD PULSE ── */
                    @keyframes arirangPulse {
                        0%, 100% {
                            box-shadow:
                                0 0 0 1px rgba(220, 30, 50, 0.6),
                                0 0 10px rgba(220, 30, 50, 0.15),
                                0 8px 25px rgba(0, 0, 0, 0.8);
                        }
                        50% {
                            box-shadow:
                                0 0 0 1px rgba(232, 58, 93, 0.95),
                                0 0 18px rgba(232, 58, 93, 0.28),
                                0 8px 25px rgba(0, 0, 0, 0.8);
                        }
                    }

                    /* ── HEADER BAR ── */
                    @keyframes topBarLive {
                        0%, 100% { opacity: 0.5; }
                        50%      { opacity: 1;   }
                    }

                    /* ── SUBTITLE BLINK ── */
                    @keyframes blinkSoft {
                        0%, 100% { opacity: 0.9; }
                        50%      { opacity: 0.4; }
                    }

                    /* ── LIVE DOT BLINK ── */
                    @keyframes liveBlink {
                        0%, 100% { opacity: 1;    transform: scale(1);    }
                        50%      { opacity: 0.25;  transform: scale(0.75); }
                    }

                    /* ── SCAN LINE ── */
                    @keyframes scanSweep {
                        0%   { top: -10%; opacity: 0;   }
                        15%  { opacity: 0.65;            }
                        80%  { opacity: 0.45;            }
                        100% { top: 115%; opacity: 0;   }
                    }

                    /* ── CRT FADE ── */
                    @keyframes crtFade {
                        0%,  50% { opacity: 0.8;  }
                        100%     { opacity: 0.06; }
                    }

                    /* ── BUTTON SHIMMER ── */
                    @keyframes btnShimmer {
                        0%   { left: -100%; }
                        18%  { left: 200%;  }
                        100% { left: 200%;  }
                    }

                    /* ══ CORNERS ══
                       Using popup- prefix so they don't
                       conflict with your global .merit-corner-tl */
                    .popup-corner-tl,
                    .popup-corner-br {
                        position: absolute;
                        width: 12px;
                        height: 12px;
                        z-index: 15;
                        pointer-events: none;
                        transition: all 0.3s ease;
                    }

                    .popup-corner-tl {
                        top: 6px;
                        left: 6px;
                        border-top: 1.5px solid rgba(232, 58, 93, 0.85);
                        border-left: 1.5px solid rgba(232, 58, 93, 0.85);
                        box-shadow: -2px -2px 6px rgba(232, 58, 93, 0.25);
                        animation: cornerPulse 3s ease-in-out infinite;
                    }

                    .popup-corner-br {
                        bottom: 6px;
                        right: 6px;
                        border-bottom: 1.5px solid rgba(232, 58, 93, 0.85);
                        border-right: 1.5px solid rgba(232, 58, 93, 0.85);
                        box-shadow: 2px 2px 6px rgba(232, 58, 93, 0.25);
                        animation: cornerPulse 3s ease-in-out infinite 1.5s;
                    }

                    @keyframes cornerPulse {
                        0%, 100% { opacity: 0.7; }
                        50%      { opacity: 1;
                                   box-shadow: 0 0 10px rgba(232, 58, 93, 0.6); }
                    }

                    /* ══ LIVE DOT ══ */
                    .popup-live-dot {
                        position: absolute;
                        top: 7px;
                        right: 7px;
                        width: 5px;
                        height: 5px;
                        background: #e83a5d;
                        border-radius: 50%;
                        z-index: 20;
                        pointer-events: none;
                        box-shadow:
                            0 0 4px rgba(232, 58, 93, 1),
                            0 0 8px rgba(232, 58, 93, 0.5);
                        animation: liveBlink 2s ease-in-out infinite;
                    }

                    /* ══ SCAN LINE ══ */
                    .popup-scanline {
                        position: absolute;
                        top: -10%;
                        left: -40%;
                        width: 180%;
                        height: 2px;
                        background: linear-gradient(90deg,
                            transparent,
                            rgba(232, 58, 93, 0.4),
                            rgba(232, 58, 93, 0.7),
                            rgba(232, 58, 93, 0.4),
                            transparent);
                        filter: blur(2px);
                        opacity: 0;
                        transform: rotate(8deg);
                        animation: scanSweep 3s ease-in-out 0.5s forwards;
                        pointer-events: none;
                        z-index: 5;
                    }

                    /* ══ CRT OVERLAY ══ */
                    .popup-crt {
                        position: absolute;
                        inset: 0;
                        background: repeating-linear-gradient(
                            0deg,
                            rgba(232, 58, 93, 0.03) 0px,
                            rgba(232, 58, 93, 0.03) 1px,
                            transparent 1px,
                            transparent 5px
                        );
                        pointer-events: none;
                        animation: crtFade 3s ease-out forwards;
                    }

                </style>
            </div>
        `;

    document.body.insertAdjacentHTML('beforeend', modalHtml);
  }
}

if (typeof window !== 'undefined') {
  window.check100XPPopup = check100XPPopup;
  // Concert Mode Arena Exports
  window.changeBombColor = window.changeBombColor;
  window.toggleStrobe = window.toggleStrobe;
  window.exitConcert = window.exitConcert;
  window.triggerGrandFinale = window.triggerGrandFinale;
  window.triggerFeverMode = window.triggerFeverMode;
  window.initiateOceanWave = window.initiateOceanWave;
  window.createFireworkBurst = createFireworkBurst;
}
